/**
 * HintChips Component (PRD v2026.02)
 *
 * Action suggestion chips that guide users during script progression.
 */
import { useState, useEffect } from 'react';
import { Sparkles, X } from 'lucide-react';
import { cn } from '@/utils/cn';

interface HintChipsProps {
  hints: string[];
  onSelect: (hint: string) => void;
  onDismiss?: () => void;
  autoHideAfter?: number;  // Milliseconds, default 30000
  className?: string;
}

export function HintChips({
  hints,
  onSelect,
  onDismiss,
  autoHideAfter = 30000,
  className,
}: HintChipsProps) {
  const [isVisible, setIsVisible] = useState(true);
  const [isAnimatingOut, setIsAnimatingOut] = useState(false);

  // Auto-hide after timeout
  useEffect(() => {
    if (autoHideAfter > 0) {
      const timer = setTimeout(() => {
        handleDismiss();
      }, autoHideAfter);

      return () => clearTimeout(timer);
    }
  }, [autoHideAfter]);

  // Reset visibility when hints change
  useEffect(() => {
    setIsVisible(true);
    setIsAnimatingOut(false);
  }, [hints]);

  const handleDismiss = () => {
    setIsAnimatingOut(true);
    setTimeout(() => {
      setIsVisible(false);
      onDismiss?.();
    }, 300);
  };

  const handleSelect = (hint: string) => {
    onSelect(hint);
    handleDismiss();
  };

  if (!isVisible || hints.length === 0) {
    return null;
  }

  return (
    <div
      className={cn(
        'flex items-center gap-2 p-2 bg-primary-500/10 border border-primary-500/30 rounded-lg',
        'transition-all duration-300',
        isAnimatingOut && 'opacity-0 translate-y-2',
        className
      )}
    >
      {/* Icon */}
      <div className="flex-shrink-0 flex items-center justify-center w-8 h-8 bg-primary-500/20 rounded-full">
        <Sparkles className="w-4 h-4 text-primary-400" />
      </div>

      {/* Chips Container */}
      <div className="flex-1 flex items-center gap-2 overflow-x-auto scrollbar-hide">
        {hints.map((hint, index) => (
          <button
            key={index}
            onClick={() => handleSelect(hint)}
            className={cn(
              'flex-shrink-0 px-3 py-1.5 rounded-full',
              'bg-zinc-800 hover:bg-zinc-700 border border-zinc-700 hover:border-zinc-600',
              'text-sm text-zinc-300 hover:text-white',
              'transition-all hover:scale-105',
              'animate-fade-in-scale'
            )}
            style={{ animationDelay: `${index * 100}ms` }}
          >
            {hint}
          </button>
        ))}
      </div>

      {/* Dismiss Button */}
      <button
        onClick={handleDismiss}
        className="flex-shrink-0 flex items-center justify-center w-6 h-6 text-zinc-500 hover:text-zinc-300 transition-colors"
        title="Dismiss hints"
      >
        <X className="w-4 h-4" />
      </button>

      {/* Custom CSS */}
      <style>{`
        @keyframes fade-in-scale {
          from {
            opacity: 0;
            transform: scale(0.9);
          }
          to {
            opacity: 1;
            transform: scale(1);
          }
        }

        .animate-fade-in-scale {
          animation: fade-in-scale 0.3s ease-out forwards;
        }

        .scrollbar-hide {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }

        .scrollbar-hide::-webkit-scrollbar {
          display: none;
        }
      `}</style>
    </div>
  );
}

/**
 * Compact variant for minimal UI
 */
export function HintChipsCompact({
  hints,
  onSelect,
}: {
  hints: string[];
  onSelect: (hint: string) => void;
}) {
  if (hints.length === 0) return null;

  return (
    <div className="flex flex-wrap gap-1.5">
      {hints.map((hint, index) => (
        <button
          key={index}
          onClick={() => onSelect(hint)}
          className={cn(
            'px-2 py-1 rounded text-xs',
            'bg-primary-500/10 hover:bg-primary-500/20',
            'text-primary-400 hover:text-primary-300',
            'border border-primary-500/30 hover:border-primary-500/50',
            'transition-all'
          )}
        >
          {hint}
        </button>
      ))}
    </div>
  );
}

/**
 * IntimacyMeter Component (PRD v2026.02)
 *
 * Displays relationship intimacy as a filling heart with smooth animations.
 */
import { useState, useEffect } from 'react';
import { Heart } from 'lucide-react';
import { cn } from '@/utils/cn';

interface IntimacyMeterProps {
  value: number;  // 0-100
  characterName: string;
  onChange?: (newValue: number) => void;  // For admin testing
  className?: string;
}

// Relationship stage thresholds
const STAGE_THRESHOLDS = {
  stranger: { min: 0, max: 10, label: 'Stranger', color: 'text-zinc-500' },
  acquaintance: { min: 10, max: 30, label: 'Acquaintance', color: 'text-blue-400' },
  friend: { min: 30, max: 50, label: 'Friend', color: 'text-green-400' },
  close_friend: { min: 50, max: 70, label: 'Close Friend', color: 'text-yellow-400' },
  companion: { min: 70, max: 90, label: 'Companion', color: 'text-orange-400' },
  intimate: { min: 90, max: 100, label: 'Intimate', color: 'text-pink-400' },
};

function getStage(value: number) {
  for (const [key, stage] of Object.entries(STAGE_THRESHOLDS)) {
    if (value >= stage.min && value < stage.max) {
      return { key, ...stage };
    }
  }
  return { key: 'intimate', ...STAGE_THRESHOLDS.intimate };
}

export function IntimacyMeter({
  value,
  characterName,
  onChange,
  className,
}: IntimacyMeterProps) {
  const [displayValue, setDisplayValue] = useState(value);
  const [showTooltip, setShowTooltip] = useState(false);
  const [previousValue, setPreviousValue] = useState(value);

  // Animate value changes
  useEffect(() => {
    if (value === displayValue) return;

    const diff = value - displayValue;
    const step = diff / 10;  // 10 animation steps
    const duration = 500;  // 500ms total animation
    const interval = duration / 10;

    let currentStep = 0;
    const timer = setInterval(() => {
      currentStep++;
      if (currentStep >= 10) {
        setDisplayValue(value);
        clearInterval(timer);
      } else {
        setDisplayValue(prev => prev + step);
      }
    }, interval);

    setPreviousValue(displayValue);

    return () => clearInterval(timer);
  }, [value]);

  const stage = getStage(displayValue);
  const fillPercentage = Math.max(0, Math.min(100, displayValue));

  // Heart fill gradient based on intimacy level
  const getHeartColor = (percentage: number): string => {
    if (percentage < 10) return '#71717a'; // zinc-500
    if (percentage < 30) return '#60a5fa'; // blue-400
    if (percentage < 50) return '#4ade80'; // green-400
    if (percentage < 70) return '#facc15'; // yellow-400
    if (percentage < 90) return '#fb923c'; // orange-400
    return '#f472b6'; // pink-400
  };

  const heartColor = getHeartColor(fillPercentage);
  const hasChanged = value !== previousValue;
  const changeAmount = value - previousValue;

  return (
    <div className={cn('relative', className)}>
      {/* Heart Icon with Fill */}
      <div
        className="relative cursor-pointer"
        onMouseEnter={() => setShowTooltip(true)}
        onMouseLeave={() => setShowTooltip(false)}
        onClick={() => onChange?.(Math.min(100, value + 10))}  // Admin: click to increase
      >
        {/* Background Heart (outline) */}
        <Heart className={cn('w-8 h-8', stage.color)} strokeWidth={2} />

        {/* Filled Heart (animated) */}
        <div
          className="absolute inset-0 overflow-hidden transition-all duration-500"
          style={{
            clipPath: `inset(${100 - fillPercentage}% 0 0 0)`,
          }}
        >
          <Heart
            className="w-8 h-8"
            fill={heartColor}
            stroke={heartColor}
            strokeWidth={2}
          />
        </div>

        {/* Pulse animation on change */}
        {hasChanged && (
          <div
            className="absolute inset-0 rounded-full animate-ping opacity-75"
            style={{
              background: `radial-gradient(circle, ${heartColor}40 0%, transparent 70%)`,
            }}
          />
        )}

        {/* Change indicator */}
        {hasChanged && Math.abs(changeAmount) > 0 && (
          <div
            className={cn(
              'absolute -top-2 -right-2 text-xs font-bold px-1.5 py-0.5 rounded-full',
              'animate-fade-in-out',
              changeAmount > 0
                ? 'bg-green-500/20 text-green-400'
                : 'bg-red-500/20 text-red-400'
            )}
          >
            {changeAmount > 0 ? '+' : ''}{changeAmount}
          </div>
        )}
      </div>

      {/* Tooltip */}
      {showTooltip && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 z-50 animate-fade-in">
          <div className="bg-zinc-900 border border-zinc-700 rounded-lg p-3 shadow-xl min-w-[180px]">
            <div className="text-sm font-medium text-white mb-1">
              {characterName}'s Intimacy
            </div>

            {/* Progress Bar */}
            <div className="relative h-2 bg-zinc-800 rounded-full overflow-hidden mb-2">
              <div
                className="absolute inset-y-0 left-0 rounded-full transition-all duration-500"
                style={{
                  width: `${fillPercentage}%`,
                  backgroundColor: heartColor,
                }}
              />
            </div>

            {/* Stage and Value */}
            <div className="flex items-center justify-between text-xs">
              <span className={cn('font-medium', stage.color)}>
                {stage.label}
              </span>
              <span className="text-zinc-400">
                {displayValue.toFixed(0)}/100
              </span>
            </div>

            {/* Stage Progress */}
            <div className="text-xs text-zinc-500 mt-1">
              {displayValue < 100 ? (
                <>
                  {Math.max(0, getStage(displayValue + 1).min - displayValue)} to{' '}
                  {getStage(displayValue + 1).label}
                </>
              ) : (
                'Maximum intimacy reached!'
              )}
            </div>
          </div>

          {/* Tooltip arrow */}
          <div className="absolute top-full left-1/2 -translate-x-1/2 -mt-px">
            <div className="w-0 h-0 border-l-4 border-r-4 border-t-4 border-l-transparent border-r-transparent border-t-zinc-700" />
          </div>
        </div>
      )}

      {/* Custom CSS for animations */}
      <style>{`
        @keyframes fade-in {
          from {
            opacity: 0;
            transform: translateY(4px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        @keyframes fade-in-out {
          0% {
            opacity: 0;
            transform: scale(0.8);
          }
          20% {
            opacity: 1;
            transform: scale(1);
          }
          80% {
            opacity: 1;
            transform: scale(1);
          }
          100% {
            opacity: 0;
            transform: scale(0.8);
          }
        }

        .animate-fade-in {
          animation: fade-in 0.2s ease-out;
        }

        .animate-fade-in-out {
          animation: fade-in-out 2s ease-out forwards;
        }
      `}</style>
    </div>
  );
}

/**
 * Compact variant for space-constrained areas
 */
export function IntimacyMeterCompact({
  value,
  className,
}: {
  value: number;
  className?: string;
}) {
  const stage = getStage(value);
  const fillPercentage = Math.max(0, Math.min(100, value));

  const getHeartColor = (percentage: number): string => {
    if (percentage < 10) return '#71717a';
    if (percentage < 30) return '#60a5fa';
    if (percentage < 50) return '#4ade80';
    if (percentage < 70) return '#facc15';
    if (percentage < 90) return '#fb923c';
    return '#f472b6';
  };

  const heartColor = getHeartColor(fillPercentage);

  return (
    <div className={cn('flex items-center gap-2', className)}>
      <div className="relative">
        <Heart className="w-5 h-5 text-zinc-600" strokeWidth={2} />
        <div
          className="absolute inset-0 overflow-hidden transition-all duration-500"
          style={{
            clipPath: `inset(${100 - fillPercentage}% 0 0 0)`,
          }}
        >
          <Heart
            className="w-5 h-5"
            fill={heartColor}
            stroke={heartColor}
            strokeWidth={2}
          />
        </div>
      </div>
      <span className={cn('text-sm font-medium', stage.color)}>
        {value.toFixed(0)}%
      </span>
    </div>
  );
}

import type { Message, NDJSONSegment } from '@/types/chat';
import { cn } from '@/utils/cn';
import { format } from 'date-fns';
import { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { ImagePreviewModal } from '../common';
import { Volume2, Loader2, Mic, Video, Play } from 'lucide-react';
import { api } from '@/services/api';
import { useAuth } from '@/contexts/AuthContext';
import { VoiceNotePlayer } from './VoiceNotePlayer';

function extractQuotedText(text: string): string {
  const chinese = text.match(/“([^”]+)”/);
  if (chinese?.[1]) return chinese[1].trim();

  const ascii = text.match(/"([^"]+)"/);
  if (ascii?.[1]) return ascii[1].trim();

  return text.trim();
}

function normalizeDialogueText(text: string): string {
  const trimmed = text.trim();
  const m = trimmed.match(/^\s*[^:：]{1,30}[:：]\s*(.*)$/);
  const rest = (m?.[1] ?? trimmed).trim();
  return extractQuotedText(rest);
}

function normalizeLegacyDialogueLines(content: string): string {
  const lines = content.split('\n');
  const normalized = lines.map((line) => {
    const m = line.match(/^\s*[^:：]{1,30}[:：]\s*[“"]/);
    if (!m) return line;
    return normalizeDialogueText(line);
  });
  return normalized.join('\n');
}

function SegmentRenderer({ segments }: { segments: NDJSONSegment[] }) {
  return (
    <div className="space-y-2">
      {segments.map((seg, idx) => {
        switch (seg.type) {
          case 'action':
            return (
              <p key={idx} className="text-zinc-400 italic text-sm">
                {seg.text}
              </p>
            );
          case 'dialogue':
            return (
              <p key={idx} className="text-white">
                {normalizeDialogueText(seg.text)}
              </p>
            );
          case 'inner':
            return (
              <p key={idx} className="text-purple-300 italic text-sm opacity-80">
                ({seg.text})
              </p>
            );
          case 'hook':
            return (
              <p key={idx} className="text-primary-300 font-medium mt-2">
                {seg.text}
              </p>
            );
          default:
            return (
              <p key={idx} className="text-white">{seg.text}</p>
            );
        }
      })}
    </div>
  );
}

interface MessageBubbleProps {
  message: Message;
  characterName?: string;
  sessionId?: string;
}

export function MessageBubble({ message, characterName, sessionId }: MessageBubbleProps) {
  const isCallReport = message.metadata?.type === 'voice_call_report';
  const isUser = message.role === 'user' || isCallReport;
  const isVoiceCall = message.metadata?.source === 'voice_call';
  const isVirtualNDJSONSegment = Boolean((message.metadata as any)?.virtual_ndjson_segment);
  const isLastVirtualNDJSONSegment = Boolean((message.metadata as any)?.virtual_ndjson_last_segment);
  const parentMessageId = (message.metadata as any)?.parent_message_id as string | undefined;
  const audioMessageId = isVirtualNDJSONSegment && parentMessageId ? parentMessageId : message.id;
  const [showImagePreview, setShowImagePreview] = useState(false);
  const [isLoadingAudio, setIsLoadingAudio] = useState(false);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);
  const [isAnimatingImage, setIsAnimatingImage] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const { refreshUser } = useAuth();

  // Detect message type and status
  const messageType = message.message_type || 'text';
  const messageStatus = message.status || 'ready';
  const isGenerating = messageStatus === 'generating';
  const isVoiceNote = messageType === 'voice_note';

  const handlePlayVoice = async () => {
    if (isUser || !sessionId) return;

    try {
      // Stop any currently playing audio
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
      setIsPlayingAudio(false);
      setIsLoadingAudio(true);

      let audioUrl = message.audio_url;
      let creditsDeducted = false;

      // If audio not cached, generate and cache it
      if (!audioUrl) {
        const response = await api.post(
          `/chat/messages/${audioMessageId}/audio?session_id=${sessionId}`
        );

        if (response.data.success && response.data.audio_url) {
          audioUrl = response.data.audio_url;
          // Update local message cache (optional - will be available on next load)
          message.audio_url = audioUrl;

          // Check if credits were deducted (not cached)
          if (!response.data.cached && response.data.credits_deducted) {
            creditsDeducted = true;
          }
        } else {
          throw new Error('Failed to generate audio');
        }
      }

      // Refresh user credits if they were deducted
      if (creditsDeducted) {
        await refreshUser();
      }

      // Create and play audio
      const audio = new Audio(audioUrl);
      audioRef.current = audio;

      audio.onloadeddata = () => {
        setIsLoadingAudio(false);
        setIsPlayingAudio(true);
      };

      audio.onended = () => {
        setIsPlayingAudio(false);
        audioRef.current = null;
      };

      audio.onerror = () => {
        setIsLoadingAudio(false);
        setIsPlayingAudio(false);
        console.error('Failed to play audio');
      };

      await audio.play();
    } catch (error: any) {
      console.error('Failed to play voice:', error);

      // Handle insufficient credits error
      if (error?.response?.status === 402) {
        const errorDetail = error.response.data?.detail;
        if (errorDetail?.error === 'insufficient_credits') {
          alert(`Insufficient credits! You need ${errorDetail.required} credits but only have ${errorDetail.available}. Please purchase more credits.`);
        }
      }

      setIsLoadingAudio(false);
      setIsPlayingAudio(false);
    }
  };

  const handleAnimateImage = async () => {
    if (!message.image_url || !sessionId) return;

    try {
      setIsAnimatingImage(true);

      const response = await api.post('/chat/animate-image', {
        message_id: message.id,
        session_id: sessionId,
      });

      if (response.data.success) {
        // Video generation is async, user will receive it via SSE
        alert('Video generation started! You will receive the animated video shortly.');
      } else {
        throw new Error('Failed to start video generation');
      }
    } catch (error: any) {
      console.error('Failed to animate image:', error);

      // Handle insufficient credits error
      if (error?.response?.status === 402) {
        const errorDetail = error.response.data?.detail;
        if (errorDetail?.error === 'insufficient_credits') {
          alert(`Insufficient credits! You need ${errorDetail.required} credits but only have ${errorDetail.available}. Please purchase more credits.`);
        }
      } else {
        alert('Failed to start video generation. Please try again.');
      }
    } finally {
      setIsAnimatingImage(false);
    }
  };

  // Cleanup audio on unmount
  useEffect(() => {
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  return (
    <div
      className={cn(
        'flex gap-3 mb-4 animate-in slide-in-from-bottom-2',
        isUser ? 'flex-row-reverse' : 'flex-row'
      )}
    >
      {/* Avatar */}
      <div
        className={cn(
          'flex-shrink-0 w-10 h-10 rounded-full flex items-center justify-center font-semibold text-sm',
          isUser
            ? 'bg-gradient-primary text-white'
            : 'bg-white/10 text-primary-400 border border-primary-500/30'
        )}
      >
        {isUser ? 'You' : characterName?.charAt(0) || 'AI'}
      </div>

      {/* Message Content */}
      <div className={cn('flex-1 max-w-[90%] sm:max-w-[80%] md:max-w-[70%]', isUser && 'flex flex-col items-end')}>
        <div
          className={cn(
            'px-4 py-3 rounded-2xl relative',
            isUser
              ? 'bg-gradient-primary text-white rounded-tr-sm'
              : 'glass-effect text-white rounded-tl-sm',
            isVoiceCall && 'border-l-4 border-purple-500' // Visual indicator for voice call messages
          )}
        >
          {/* Voice Call Badge */}
          {isVoiceCall && (
            <div className="absolute -top-2 -left-2 bg-purple-500 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 shadow-lg">
              <Mic size={12} />
              <span>Voice</span>
            </div>
          )}

          {/* Generating Status Skeleton Loader */}
          {isGenerating ? (
            <div className="space-y-2 animate-pulse">
              <div className="h-4 bg-zinc-700/50 rounded w-3/4"></div>
              <div className="h-4 bg-zinc-700/50 rounded w-full"></div>
              <div className="h-4 bg-zinc-700/50 rounded w-5/6"></div>
              <div className="flex items-center gap-2 mt-3 text-sm text-zinc-500">
                <Loader2 size={16} className="animate-spin" />
                <span>Generating {messageType}...</span>
              </div>
            </div>
          ) : isVoiceNote && message.audio_url ? (
            // Voice Note Player
            <VoiceNotePlayer
              audioUrl={message.audio_url}
              duration={message.duration || 0}
              isGenerating={false}
              cost={message.cost}
            />
          ) : isCallReport ? (
            <div className="flex items-center gap-2 text-base font-medium min-w-[180px] justify-between">
              <span>{message.content}</span>
              <Video size={20} className="text-white/80" />
            </div>
          ) : message.isNDJSON && message.segments && message.segments.length > 0 ? (
            <div className={cn(
              "max-w-none break-words",
              !isUser && !message.image_url && !message.video_url && "pr-12"
            )}>
              <SegmentRenderer segments={message.segments} />
            </div>
          ) : (
            <div className={cn(
              "prose prose-invert prose-sm max-w-none break-words [&>*:first-child]:mt-0 [&>*:last-child]:mb-0",
              !isUser && !message.image_url && !message.video_url && "pr-12"
            )}>
              <ReactMarkdown remarkPlugins={[remarkGfm]}>
                {isUser ? message.content : normalizeLegacyDialogueLines(message.content)}
              </ReactMarkdown>
            </div>
          )}

          {/* Voice Button for Character Messages - Only show on text-only messages */}
          {!isUser && !message.image_url && !message.video_url && !isCallReport && (!isVirtualNDJSONSegment || isLastVirtualNDJSONSegment) && (
            <button
              onClick={handlePlayVoice}
              disabled={isLoadingAudio}
              className={cn(
                'absolute top-2 right-2 w-10 h-10 rounded-full flex items-center justify-center transition-all shadow-lg',
                'bg-white/10 hover:bg-white/20 backdrop-blur-sm border border-white/20',
                isPlayingAudio && 'bg-primary-500/50 border-primary-400',
                'disabled:opacity-50 disabled:cursor-not-allowed'
              )}
              title="Play voice (5 credits)"
            >
              {isLoadingAudio ? (
                <Loader2 size={20} className="text-white animate-spin" />
              ) : (
                <Volume2 size={20} className={cn('text-white', isPlayingAudio && 'animate-pulse')} />
              )}
            </button>
          )}
          {message.image_url && !isGenerating && (
            <>
              <div className="mt-3 rounded-lg overflow-hidden relative group">
                <img
                  src={message.image_url}
                  alt="Generated content"
                  className="w-full h-auto max-w-full sm:max-w-[300px] object-cover cursor-pointer hover:opacity-90 transition-opacity"
                  loading="lazy"
                  onClick={() => setShowImagePreview(true)}
                />

                {/* Animate Button (Image to Video) */}
                {!isUser && sessionId && (
                  <button
                    onClick={handleAnimateImage}
                    disabled={isAnimatingImage}
                    className={cn(
                      'absolute bottom-2 right-2 px-3 py-1.5 rounded-lg',
                      'bg-primary-500/90 hover:bg-primary-600/90 text-white text-sm font-medium',
                      'flex items-center gap-1.5 shadow-lg backdrop-blur-sm',
                      'opacity-0 group-hover:opacity-100 transition-all',
                      'disabled:opacity-50 disabled:cursor-not-allowed'
                    )}
                    title="Convert to animated video"
                  >
                    {isAnimatingImage ? (
                      <>
                        <Loader2 size={16} className="animate-spin" />
                        <span>Animating...</span>
                      </>
                    ) : (
                      <>
                        <Play size={16} fill="white" />
                        <span>Animate</span>
                      </>
                    )}
                  </button>
                )}
              </div>
              <ImagePreviewModal
                isOpen={showImagePreview}
                onClose={() => setShowImagePreview(false)}
                imageUrl={message.image_url}
              />
            </>
          )}
          {message.video_url && !isGenerating && (
            <div className="mt-3 rounded-lg overflow-hidden">
              <video
                src={message.video_url}
                controls
                className="w-full h-auto max-w-full sm:max-w-[300px]"
                playsInline
              />
            </div>
          )}
        </div>
        <span className="text-xs text-zinc-500 mt-1 px-1">
          {(() => {
            try {
              const dateStr = message.timestamp || (message as any).created_at;
              if (!dateStr) return '';
              return format(new Date(dateStr), 'HH:mm');
            } catch (e) {
              return '';
            }
          })()}
        </span>
      </div>
    </div>
  );
}

/**
 * ScriptSelector Component (PRD v2026.02)
 *
 * Browse and select scripts for characters.
 */
import { useState, useEffect } from 'react';
import { Play, Lock, Tag } from 'lucide-react';
import { cn } from '@/utils/cn';
import type { Script } from '@/types/script';
import { api } from '@/services/api';

interface ScriptSelectorProps {
  characterId: string;
  onScriptSelect: (scriptId: string) => void;
  className?: string;
}

export function ScriptSelector({
  characterId,
  onScriptSelect,
  className,
}: ScriptSelectorProps) {
  const [scripts, setScripts] = useState<Script[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchScripts();
  }, [characterId]);

  const fetchScripts = async () => {
    try {
      setIsLoading(true);
      setError(null);

      const response = await api.get(`/v2/scripts/characters/${characterId}/scripts`);
      setScripts(response.data || []);
    } catch (err: any) {
      console.error('Failed to fetch scripts:', err);
      setError(err.response?.data?.detail || 'Failed to load scripts');
    } finally {
      setIsLoading(false);
    }
  };

  const handleStartScript = (scriptId: string) => {
    onScriptSelect(scriptId);
  };

  if (isLoading) {
    return (
      <div className={cn('space-y-3', className)}>
        <div className="text-sm font-medium text-zinc-400">Loading scripts...</div>
        <div className="flex gap-3 overflow-x-auto pb-2">
          {[1, 2, 3].map((i) => (
            <div
              key={i}
              className="flex-shrink-0 w-64 h-32 bg-zinc-800/50 rounded-lg animate-pulse"
            />
          ))}
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className={cn('text-sm text-red-400', className)}>
        {error}
      </div>
    );
  }

  if (scripts.length === 0) {
    return (
      <div className={cn('text-sm text-zinc-500', className)}>
        No scripts available for this character yet.
      </div>
    );
  }

  return (
    <div className={cn('space-y-3', className)}>
      <div className="text-sm font-medium text-zinc-400">
        What If Scenarios
      </div>

      <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
        {scripts.map((script) => (
          <ScriptCard
            key={script.id}
            script={script}
            onStart={() => handleStartScript(script.id)}
          />
        ))}
      </div>
    </div>
  );
}

function ScriptCard({
  script,
  onStart,
}: {
  script: Script;
  onStart: () => void;
}) {
  return (
    <div className="flex-shrink-0 w-64 bg-zinc-900/50 border border-zinc-800 hover:border-zinc-700 rounded-lg p-4 transition-all hover:shadow-lg group">
      {/* Header */}
      <div className="flex items-start justify-between mb-2">
        <div className="flex-1">
          <h3 className="text-sm font-medium text-white line-clamp-1">
            {script.name}
          </h3>
          <p className="text-xs text-zinc-500 mt-0.5">
            {script.context.location} • {script.context.time}
          </p>
        </div>
        {script.is_official && (
          <div className="flex-shrink-0 ml-2">
            <div className="px-2 py-0.5 bg-primary-500/20 text-primary-400 text-xs rounded">
              Official
            </div>
          </div>
        )}
      </div>

      {/* Description */}
      <p className="text-xs text-zinc-400 line-clamp-2 mb-3">
        {script.description}
      </p>

      {/* Tags */}
      {script.tags.length > 0 && (
        <div className="flex flex-wrap gap-1 mb-3">
          {script.tags.slice(0, 3).map((tag, i) => (
            <div
              key={i}
              className="flex items-center gap-1 px-1.5 py-0.5 bg-zinc-800 rounded text-xs text-zinc-500"
            >
              <Tag className="w-3 h-3" />
              {tag}
            </div>
          ))}
        </div>
      )}

      {/* Start Button */}
      <button
        onClick={onStart}
        className={cn(
          'w-full flex items-center justify-center gap-2 px-3 py-2 rounded-lg',
          'bg-primary-500 hover:bg-primary-600 text-white text-sm font-medium',
          'transition-all group-hover:scale-105'
        )}
      >
        <Play className="w-4 h-4" fill="white" />
        Start Script
      </button>
    </div>
  );
}

