/**
 * VoiceNotePlayer Component (PRD v2026.02)
 *
 * Audio player for voice note messages with waveform visualization.
 */
import { useState, useRef, useEffect } from 'react';
import { Play, Pause, Download, Loader2 } from 'lucide-react';
import { cn } from '@/utils/cn';

interface VoiceNotePlayerProps {
  audioUrl: string;
  duration: number;  // Duration in seconds
  isGenerating?: boolean;
  cost?: number;
  onPlayStart?: () => void;
  onPlayEnd?: () => void;
}

export function VoiceNotePlayer({
  audioUrl,
  duration,
  isGenerating = false,
  cost,
  onPlayStart,
  onPlayEnd,
}: VoiceNotePlayerProps) {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [isLoading, setIsLoading] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Format time as MM:SS
  const formatTime = (seconds: number): string => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Initialize audio element
  useEffect(() => {
    if (!audioUrl || isGenerating) return;

    const audio = new Audio(audioUrl);
    audioRef.current = audio;

    audio.addEventListener('loadstart', () => setIsLoading(true));
    audio.addEventListener('canplay', () => setIsLoading(false));
    audio.addEventListener('timeupdate', () => {
      setCurrentTime(audio.currentTime);
    });
    audio.addEventListener('ended', () => {
      setIsPlaying(false);
      setCurrentTime(0);
      onPlayEnd?.();
    });

    return () => {
      audio.pause();
      audio.src = '';
      audioRef.current = null;
    };
  }, [audioUrl, isGenerating, onPlayEnd]);

  const handlePlayPause = () => {
    if (!audioRef.current) return;

    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      audioRef.current.play().catch((error) => {
        console.error('Audio playback error:', error);
      });
      setIsPlaying(true);
      onPlayStart?.();
    }
  };

  const handleDownload = () => {
    if (!audioUrl) return;

    const a = document.createElement('a');
    a.href = audioUrl;
    a.download = `voice-note-${Date.now()}.wav`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const handleSeek = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!audioRef.current || !duration) return;

    const rect = e.currentTarget.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const percentage = x / rect.width;
    const newTime = percentage * duration;

    audioRef.current.currentTime = newTime;
    setCurrentTime(newTime);
  };

  // Show skeleton loader while generating
  if (isGenerating) {
    return (
      <div className="flex items-center gap-3 p-3 bg-zinc-800/50 rounded-lg border border-zinc-700/50">
        <div className="flex items-center justify-center w-10 h-10 bg-primary-500/20 rounded-full">
          <Loader2 className="w-5 h-5 text-primary-400 animate-spin" />
        </div>
        <div className="flex-1 space-y-2">
          <div className="h-8 bg-zinc-700/50 rounded animate-pulse" />
          <div className="text-xs text-zinc-500">Generating voice note...</div>
        </div>
      </div>
    );
  }

  const progress = duration > 0 ? (currentTime / duration) * 100 : 0;

  return (
    <div className="flex items-center gap-3 p-3 bg-zinc-800/50 rounded-lg border border-zinc-700/50 hover:border-zinc-600/50 transition-colors">
      {/* Play/Pause Button */}
      <button
        onClick={handlePlayPause}
        disabled={isLoading}
        className={cn(
          'flex items-center justify-center w-10 h-10 rounded-full transition-all',
          'bg-primary-500 hover:bg-primary-600 disabled:bg-zinc-700',
          'focus:outline-none focus:ring-2 focus:ring-primary-400/50'
        )}
      >
        {isLoading ? (
          <Loader2 className="w-5 h-5 text-white animate-spin" />
        ) : isPlaying ? (
          <Pause className="w-5 h-5 text-white" fill="white" />
        ) : (
          <Play className="w-5 h-5 text-white ml-0.5" fill="white" />
        )}
      </button>

      {/* Waveform / Progress Bar */}
      <div className="flex-1 space-y-1">
        {/* Progress Bar */}
        <div
          className="relative h-8 bg-zinc-700/50 rounded cursor-pointer group"
          onClick={handleSeek}
        >
          {/* Progress Fill */}
          <div
            className="absolute inset-y-0 left-0 bg-primary-500/30 rounded transition-all"
            style={{ width: `${progress}%` }}
          />

          {/* Waveform Visualization (simplified bars) */}
          <div className="absolute inset-0 flex items-center justify-around px-1">
            {Array.from({ length: 40 }).map((_, i) => {
              const height = 20 + Math.sin(i * 0.5) * 15 + Math.random() * 10;
              const isPassed = (i / 40) * 100 < progress;

              return (
                <div
                  key={i}
                  className={cn(
                    'w-0.5 rounded-full transition-colors',
                    isPassed ? 'bg-primary-400' : 'bg-zinc-600'
                  )}
                  style={{ height: `${height}%` }}
                />
              );
            })}
          </div>

          {/* Hover indicator */}
          <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
            <div className="absolute inset-y-0 right-0 w-px bg-white/20" />
          </div>
        </div>

        {/* Time Display */}
        <div className="flex items-center justify-between text-xs text-zinc-400">
          <span>{formatTime(currentTime)}</span>
          <span>{formatTime(duration)}</span>
        </div>
      </div>

      {/* Download Button */}
      <button
        onClick={handleDownload}
        className={cn(
          'flex items-center justify-center w-8 h-8 rounded-full transition-colors',
          'text-zinc-400 hover:text-white hover:bg-zinc-700'
        )}
        title="Download voice note"
      >
        <Download className="w-4 h-4" />
      </button>

      {/* Cost Indicator (if available) */}
      {cost !== undefined && cost > 0 && (
        <div className="text-xs text-zinc-500 ml-1">
          {cost.toFixed(2)} credits
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { X, Image as ImageIcon, Video, Loader2 } from 'lucide-react';
import { api } from '@/services/api';

interface GalleryItem {
  id: string;
  image_url?: string;
  video_url?: string;
  created_at: string;
  content?: string;
}

interface GalleryModalProps {
  isOpen: boolean;
