export function VideoCharacterGrid({ characters = VIDEO_CHARACTERS }: { characters?: any[] }) {
  const navigate = useNavigate();
  const { isAuthenticated } = useAuth();
  const [activeVideo, setActiveVideo] = useState<string | null>(null);
  const [muted, setMuted] = useState(true);
  const [loadingId, setLoadingId] = useState<string | null>(null);
  const videoRefs = useRef<{ [key: string]: HTMLVideoElement }>({});
  const formatVersion = (value?: string) => {
    if (!value) return '';
    return value.startsWith('v') ? value : `v${value}`;
  };

  const displayCharacters = useMemo(() => {
    if (!Array.isArray(characters)) return [];
    return characters.map((char) => {
      let videoSrc = char.video;
      // If videos list exists and has items, pick a random one
      if (char.videos && Array.isArray(char.videos) && char.videos.length > 0) {
        const randomIndex = Math.floor(Math.random() * char.videos.length);
        videoSrc = char.videos[randomIndex];
      }

      return {
        ...char,
        displayVideo: videoSrc || null
      };
    });
  }, [characters]);

  const handleChat = async (e: React.MouseEvent, char: any) => {
    e.stopPropagation();

    if (!char.id) {
      // If authenticated, go to chat, otherwise go to register
      navigate(isAuthenticated ? '/chat' : '/register');
      return;
    }

    // Guest mode: Navigate directly to guest chat
    if (!isAuthenticated) {
      navigate(`/chat?character=${char.id}&mode=guest`);
      return;
    }

    // Authenticated: Copy official character and navigate
    try {
      setLoadingId(char.id);
      const response = await api.post(`/chat/chat_now_official/${char.id}`);
      const userCharacterId = response.data?.character_id;

      if (!userCharacterId) {
        throw new Error('Failed to get character ID from response');
      }

      // Navigate with the user's character copy ID
      navigate(`/chat?character=${userCharacterId}&ready=1`);
    } catch (error) {
      console.error('Failed to start chat:', error);
      alert('Failed to start chat. Please try again.');
    } finally {
      setLoadingId(null);
    }
  };

  const handleMouseEnter = (id: string) => {
    const char = displayCharacters.find((item) => item.id === id);
    if (!char?.displayVideo) return;

    setActiveVideo(id);
    if (videoRefs.current[id]) {
      videoRefs.current[id].play().catch(() => {
        // Autoplay might be blocked
      });
    }
  };

  const handleMouseLeave = (id: string) => {
    setActiveVideo(null);
    if (videoRefs.current[id]) {
      videoRefs.current[id].pause();
      videoRefs.current[id].currentTime = 0;
    }
  };

  const toggleMute = (e: React.MouseEvent) => {
    e.stopPropagation();
    setMuted(!muted);
  };

  return (
    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-6">
      {displayCharacters.map((char) => (
        <div 
          key={char.id}
          className="group relative aspect-[3/4] rounded-xl overflow-hidden cursor-pointer"
          onMouseEnter={() => handleMouseEnter(char.id)}
          onMouseLeave={() => handleMouseLeave(char.id)}
          onClick={(e) => handleChat(e, char)}
        >
          {/* Static Image */}
          <div className={cn(
            "absolute inset-0 transition-opacity duration-500",
            activeVideo === char.id ? "opacity-0" : "opacity-100"
          )}>
            <img 
              src={char.image} 
              alt={char.name}
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent"></div>
          </div>

          {/* Video Layer */}
          {char.displayVideo && (
            <div className={cn(
              "absolute inset-0 transition-opacity duration-500 bg-black",
              activeVideo === char.id ? "opacity-100" : "opacity-0"
            )}>
              <video
                ref={el => { if (el) videoRefs.current[char.id] = el }}
                src={char.displayVideo}
                className="w-full h-full object-cover"
                loop
                muted={muted}
                playsInline
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent"></div>

              <button
                onClick={toggleMute}
                className="absolute top-3 right-3 p-2 rounded-full bg-black/50 hover:bg-black/70 text-white transition-colors"
              >
                {muted ? <VolumeX size={16} /> : <Volume2 size={16} />}
              </button>
            </div>
          )}

          {/* Info Overlay */}
          <div className="absolute bottom-0 left-0 right-0 p-4 transform transition-transform duration-300 group-hover:translate-y-0 translate-y-2">
            <div className="space-y-2">
              <h3 className="text-lg font-bold text-white">{char.name}</h3>
              <p className="text-xs text-zinc-200/90 line-clamp-3 leading-relaxed transition-opacity duration-200 group-hover:opacity-0">
                {char.desc || 'AI Companion'}
              </p>
              <div className="pointer-events-none absolute left-4 right-4 top-11 opacity-0 transition-opacity duration-200 group-hover:opacity-100">
                {char.storyTitle && (
                  <p className="text-[11px] uppercase tracking-wide text-primary-300/90">
                    {char.storyTitle}
                  </p>
                )}
                <p className="mt-1 text-xs text-zinc-100 line-clamp-4 leading-relaxed">
                  {char.storyDescription || 'No opening script available yet.'}
                </p>
              </div>
            </div>

            <div className="mt-3 flex items-center justify-end text-xs text-zinc-400">
              <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity duration-300 delay-100">
                {loadingId === char.id ? (
                  <Loader2 size={12} className="text-primary-400 animate-spin" />
                ) : (
                  <Play size={12} className="text-primary-400 fill-primary-400" />
                )}
                <span className="text-xs font-medium text-primary-400">
                  {loadingId === char.id ? 'Loading...' : 'Chat Now'}
                </span>
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

/**
 * Script Preview Component
 * 
 * Preview script structure and flow
 */

import React from 'react';
import { Card } from '../common/Card';

interface SceneConfig {
  scene_id: string;
  name: string;
  description: string;
  atmosphere: string;
}

interface ScriptTrigger {
  trigger_id: string;
  name: string;
  trigger_type: string;
  target_scene_id?: string;
}

interface ScriptPreviewProps {
  title: string;
  description: string;
  genre: string;
  worldSetting: string;
  openingLine: string;
  scenes: SceneConfig[];
  triggers: ScriptTrigger[];
  startSceneId?: string;
}

export const ScriptPreview: React.FC<ScriptPreviewProps> = ({
  title,
  description,
  genre,
  worldSetting,
  openingLine,
  scenes,
  triggers,
  startSceneId,
}) => {
  const startScene = scenes.find(s => s.scene_id === startSceneId) || scenes[0];
  
  return (
    <div className="script-preview space-y-6">
      {/* Title card */}
      <Card className="p-6 bg-gradient-to-br from-purple-900/50 to-pink-900/50 border-purple-500/30">
        <div className="flex items-start justify-between">
          <div>
            <h1 className="text-2xl font-bold text-white">{title || 'Untitled Script'}</h1>
            <p className="text-gray-300 mt-2">{description || 'No description yet'}</p>
          </div>
          <span className="px-3 py-1 bg-purple-600/50 text-purple-200 rounded-full text-sm">
            {genre}
          </span>
        </div>
        
        {worldSetting && (
          <div className="mt-4 p-3 bg-black/20 rounded-lg">
            <p className="text-gray-400 text-sm">World setting</p>
            <p className="text-gray-200">{worldSetting}</p>
          </div>
        )}
        
        {openingLine && (
          <div className="mt-4 p-3 bg-black/20 rounded-lg border-l-4 border-purple-500">
            <p className="text-gray-400 text-sm">Opening Line</p>
            <p className="text-white italic">"{openingLine}"</p>
          </div>
        )}
      </Card>
      
      {/* Scene flow diagram */}
      <Card className="p-6 bg-gray-800/50">
        <h2 className="text-lg font-semibold text-white mb-4">Scene Flow</h2>
        
        {scenes.length === 0 ? (
          <p className="text-gray-400 text-center py-8">No scenes yet, please add scenes first</p>
        ) : (
          <div className="space-y-4">
            {scenes.map((scene, index) => {
              const isStart = scene.scene_id === startSceneId || (index === 0 && !startSceneId);
              const incomingTriggers = triggers.filter(t => t.target_scene_id === scene.scene_id);
              
              return (
                <div key={scene.scene_id} className="relative">
                  {/* Connector */}
                  {index > 0 && (
                    <div className="absolute left-6 -top-4 w-0.5 h-4 bg-gray-600" />
                  )}
                  
                  <div className={`flex items-start gap-4 p-4 rounded-lg ${
                    isStart ? 'bg-green-900/30 border border-green-500/30' : 'bg-gray-700/50'
                  }`}>
                    {/* Scene marker */}
                    <div className={`w-12 h-12 rounded-lg flex items-center justify-center text-white font-bold ${
                      isStart ? 'bg-green-600' : 'bg-purple-600'
                    }`}>
                      {index + 1}
                    </div>
                    
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <h3 className="text-white font-semibold">{scene.name}</h3>
                        {isStart && (
                          <span className="px-2 py-0.5 bg-green-600/50 text-green-200 text-xs rounded">
                            Start Scene
                          </span>
                        )}
                      </div>
                      <p className="text-gray-400 text-sm mt-1">{scene.description}</p>
                      
                      {/* Trigger entries */}
                      {incomingTriggers.length > 0 && (
                        <div className="flex flex-wrap gap-2 mt-2">
                          {incomingTriggers.map(trigger => (
                            <span
                              key={trigger.trigger_id}
                              className="px-2 py-1 bg-yellow-600/30 text-yellow-300 text-xs rounded flex items-center gap-1"
                            >
                              ← {trigger.name}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>
                    
                    <span className="px-2 py-1 bg-blue-600/30 text-blue-300 text-xs rounded">
                      {scene.atmosphere}
                    </span>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </Card>
      
      {/* Trigger list */}
      {triggers.length > 0 && (
        <Card className="p-6 bg-gray-800/50">
          <h2 className="text-lg font-semibold text-white mb-4">Triggers ({triggers.length})</h2>
          
          <div className="grid gap-3 md:grid-cols-2">
            {triggers.map(trigger => (
              <div
                key={trigger.trigger_id}
                className="p-3 bg-gray-700/50 rounded-lg flex items-center justify-between"
              >
                <div>
                  <p className="text-white text-sm">{trigger.name}</p>
                  <p className="text-gray-400 text-xs">{trigger.trigger_type}</p>
                </div>
                {trigger.target_scene_id && (
                  <span className="text-green-400 text-xs">
                    → {scenes.find(s => s.scene_id === trigger.target_scene_id)?.name || '?'}
                  </span>
                )}
              </div>
            ))}
          </div>
        </Card>
      )}
    </div>
  );
};

