import { createContext, useContext, useState, useEffect, useCallback } from 'react';
import type { ReactNode } from 'react';
import axios from 'axios';

const API_BASE = import.meta.env.VITE_API_BASE_URL || '/api';

interface GeoState {
  allowed: boolean;
  countryCode: string;
  countryName: string;
  isLoading: boolean;
  isChecked: boolean;
}

interface GeoContextValue extends GeoState {
  recheckGeo: () => Promise<void>;
}

const GeoContext = createContext<GeoContextValue | undefined>(undefined);

const GEO_CACHE_KEY = 'aigirl_geo_check';
const GEO_CACHE_TTL = 1000 * 60 * 60; // 1 hour cache

interface CachedGeoData {
  allowed: boolean;
  countryCode: string;
  countryName: string;
  timestamp: number;
}

function getCachedGeo(): CachedGeoData | null {
  try {
    const cached = localStorage.getItem(GEO_CACHE_KEY);
    if (!cached) return null;

    const data: CachedGeoData = JSON.parse(cached);
    const now = Date.now();

    // Check if cache is still valid
    if (now - data.timestamp < GEO_CACHE_TTL) {
      return data;
    }

    // Cache expired
    localStorage.removeItem(GEO_CACHE_KEY);
    return null;
  } catch {
    return null;
  }
}

function setCachedGeo(data: Omit<CachedGeoData, 'timestamp'>): void {
  try {
    const cacheData: CachedGeoData = {
      ...data,
      timestamp: Date.now(),
    };
    localStorage.setItem(GEO_CACHE_KEY, JSON.stringify(cacheData));
  } catch {
    // Ignore localStorage errors
  }
}

export function useGeoContext() {
  const context = useContext(GeoContext);
  if (!context) {
    throw new Error('useGeoContext must be used within GeoProvider');
  }
  return context;
}

interface GeoProviderProps {
  children: ReactNode;
}

export function GeoProvider({ children }: GeoProviderProps) {
  const [state, setState] = useState<GeoState>({
    allowed: true, // Default to allowed until check completes
    countryCode: '',
    countryName: '',
    isLoading: true,
    isChecked: false,
  });

  const checkGeo = useCallback(async () => {
    // Check cache first
    const cached = getCachedGeo();
    if (cached) {
      setState({
        allowed: cached.allowed,
        countryCode: cached.countryCode,
        countryName: cached.countryName,
        isLoading: false,
        isChecked: true,
      });
      return;
    }

    setState(prev => ({ ...prev, isLoading: true }));

    try {
      const response = await axios.get(`${API_BASE}/geo/check`);
      const { allowed, country_code, country_name } = response.data;

      // Cache the result
      setCachedGeo({
        allowed,
        countryCode: country_code,
        countryName: country_name,
      });

      setState({
        allowed,
        countryCode: country_code,
        countryName: country_name,
        isLoading: false,
        isChecked: true,
      });
    } catch (error) {
      console.error('Geo check failed:', error);
      // On error, default to allowed (fail open)
      setState({
        allowed: true,
        countryCode: 'UNKNOWN',
        countryName: 'Unknown',
        isLoading: false,
        isChecked: true,
      });
    }
  }, []);

  const recheckGeo = useCallback(async () => {
    // Clear cache and recheck
    localStorage.removeItem(GEO_CACHE_KEY);
    await checkGeo();
  }, [checkGeo]);

  // Check geo on mount
  useEffect(() => {
    checkGeo();
  }, [checkGeo]);

  const value: GeoContextValue = {
    ...state,
    recheckGeo,
  };

  return <GeoContext.Provider value={value}>{children}</GeoContext.Provider>;
}

import { createContext, useContext, useState, useCallback, useEffect } from 'react';
import type { ReactNode } from 'react';
import axios from 'axios';

const API_BASE = import.meta.env.VITE_API_BASE_URL || '/api';

export interface GuestMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  image_url?: string;
  video_url?: string;
  audio_url?: string;
  timestamp: string;
}

interface GuestContextValue {
  isGuestMode: boolean;
  setIsGuestMode: (value: boolean) => void;
  guestCredits: number;
  isCreditsExhausted: boolean;
  guestMessages: GuestMessage[];
  fetchGuestCredits: () => Promise<void>;
  sendGuestMessage: (characterId: string, message: string) => Promise<GuestMessage | null>;
  clearGuestMessages: () => void;
  isLoading: boolean;
  isSending: boolean;
}

const GuestContext = createContext<GuestContextValue | undefined>(undefined);

export function useGuestContext() {
  const context = useContext(GuestContext);
  if (!context) {
    throw new Error('useGuestContext must be used within GuestProvider');
  }
  return context;
}

interface GuestProviderProps {
  children: ReactNode;
}

export function GuestProvider({ children }: GuestProviderProps) {
  const [isGuestMode, setIsGuestMode] = useState(false);
  const [guestCredits, setGuestCredits] = useState(20);
  const [isCreditsExhausted, setIsCreditsExhausted] = useState(false);
  const [guestMessages, setGuestMessages] = useState<GuestMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSending, setIsSending] = useState(false);

  const fetchGuestCredits = useCallback(async () => {
    setIsLoading(true);
    try {
      const response = await axios.get(`${API_BASE}/chat/guest/credits`);
      setGuestCredits(response.data.credits);
      setIsCreditsExhausted(response.data.is_exhausted);
    } catch (error) {
      console.error('Failed to fetch guest credits:', error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const sendGuestMessage = useCallback(async (
    characterId: string,
    message: string
  ): Promise<GuestMessage | null> => {
    if (isSending) return null;

    setIsSending(true);

    // Add user message immediately (optimistic)
    const userMsg: GuestMessage = {
      id: `guest-user-${Date.now()}`,
      role: 'user',
      content: message,
      timestamp: new Date().toISOString()
    };
    setGuestMessages(prev => [...prev, userMsg]);

    try {
      const response = await axios.post(`${API_BASE}/chat/guest/send`, {
        character_id: characterId,
        message: message
      });

      const assistantMsg: GuestMessage = {
        id: `guest-assistant-${Date.now()}`,
        role: 'assistant',
        content: response.data.content,
        image_url: response.data.image_url || undefined,
        video_url: response.data.video_url || undefined,
        audio_url: response.data.audio_url || undefined,
        timestamp: new Date().toISOString()
      };

      setGuestMessages(prev => [...prev, assistantMsg]);
      setGuestCredits(response.data.credits_remaining);
      setIsCreditsExhausted(response.data.is_exhausted);

      return assistantMsg;
    } catch (error: unknown) {
      console.error('Guest message failed:', error);

      // Check if credits exhausted
      if (axios.isAxiosError(error) && error.response?.status === 402) {
        setIsCreditsExhausted(true);
        setGuestCredits(0);
      }

      // Remove optimistic user message on error
      setGuestMessages(prev => prev.filter(m => m.id !== userMsg.id));
      return null;
    } finally {
      setIsSending(false);
    }
  }, [isSending]);

  const clearGuestMessages = useCallback(() => {
    setGuestMessages([]);
  }, []);

  // Fetch credits when entering guest mode
  useEffect(() => {
    if (isGuestMode) {
      fetchGuestCredits();
    } else {
      // Clear messages when exiting guest mode
      setGuestMessages([]);
    }
  }, [isGuestMode, fetchGuestCredits]);

  const value: GuestContextValue = {
    isGuestMode,
    setIsGuestMode,
    guestCredits,
    isCreditsExhausted,
    guestMessages,
    fetchGuestCredits,
    sendGuestMessage,
    clearGuestMessages,
    isLoading,
    isSending,
  };

  return <GuestContext.Provider value={value}>{children}</GuestContext.Provider>;
}

import { useState, useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { ChatProvider, useChatContext } from '@/contexts/ChatContext';
import { useAuth } from '@/contexts/AuthContext';
import {
  CharacterSelector,
  MessageList,
  ChatInput,
  ConsentModal,
  SceneBanner,
} from '@/components/chat';
import { IntimacyMeterCompact } from '@/components/chat/IntimacyMeter';
import { SceneChoices } from '@/components/chat/SceneChoices';
import { StoryCompletionModal } from '@/components/story';
import { RelationshipLockModal } from '@/components/character/RelationshipLockModal';
import { Button, GalleryModal } from '@/components/common';
import { Menu, Sparkles, AlertCircle, Image, Coins, Home, ShieldCheck } from 'lucide-react';
import { api } from '@/services/api';
import type { Character } from '@/types';

function ChatContent() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { user } = useAuth();
  const {
    currentCharacter,
    setCurrentCharacter,
    messages,
    sessionId,
    isLoading: isSessionLoading,
    isTyping,
    sendMessage,
    // PRD v3: Scene gameplay
    sceneChoices,
    clearSceneChoices,
    // Intimacy tracking
    intimacy,
    relationshipStage,
    // Story completion
    storyCompletedData,
    clearStoryCompletedData,
    // Scene banner
    sceneBanner,
  } = useChatContext();

  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [loadingCharacter, setLoadingCharacter] = useState(false);
  const [error, setError] = useState('');
  const [isGalleryOpen, setIsGalleryOpen] = useState(false);
  // PRD v2026.02: Relationship locking
  const [showRelationshipLockModal, setShowRelationshipLockModal] = useState(false);
  const [lockingRelationship, setLockingRelationship] = useState(false);
  const [showConsentModal, setShowConsentModal] = useState(false);
  const [pendingMessage, setPendingMessage] = useState<string | null>(null);
  const chatBackdrop =
    currentCharacter?.profile_image_url || currentCharacter?.media_urls?.avatar;

  // Load character from URL parameter
  useEffect(() => {
    const characterId = searchParams.get('character');
    if (characterId && !currentCharacter) {
      loadCharacter(characterId);
    }
  }, [searchParams]);

  const loadCharacter = async (characterId: string) => {
    setLoadingCharacter(true);
    setError('');
    try {
      // Add 15s timeout to prevent infinite loading
      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error('Request timed out')), 15000)
      );

      const response = await Promise.race([
        api.get<Character>(`/characters/${characterId}`),
        timeoutPromise
      ]) as any;

      const data: any = response.data;
      const sanitize = (u?: string) => (typeof u === 'string' ? u.replace(/`/g, '').trim() : undefined);
      const pvRaw = typeof data?.video_url === 'object' ? data.video_url : data.profile_videos;
      const pv = pvRaw
        ? {
            IDLE_VIDEO_URL: sanitize(pvRaw.IDLE_VIDEO_URL) || pvRaw.IDLE_VIDEO_URL,
            TALKING_VIDEO_URL: sanitize(pvRaw.TALKING_VIDEO_URL) || pvRaw.TALKING_VIDEO_URL,
          }
        : undefined;
      setCurrentCharacter({ ...data, profile_videos: pv });
    } catch (err: any) {
      console.error('Failed to load character:', err);
      setError('Failed to load character. Please try again or select another character.');
    } finally {
      setLoadingCharacter(false);
    }
  };

  const handleSelectCharacter = (character: Character) => {
    setCurrentCharacter(character);
    // Update URL
    navigate(`/chat?character=${character.id}`, { replace: true });
  };

  const handleSendMessage = async (content: string) => {
    setError('');

    // PRD v2026.02: Check if relationship needs to be locked
    if (
      currentCharacter &&
      !currentCharacter.relationship_locked &&
      currentCharacter.relationship_role &&
      currentCharacter.user_role &&
      messages.length === 0 // First message
    ) {
      // Show lock confirmation modal
      setPendingMessage(content);
      setShowRelationshipLockModal(true);
      return;
    }

    try {
      await sendMessage(content);
    } catch (err: any) {
      console.error('Failed to send message:', err);
      setError('Failed to send message. Please try again.');
    }
  };

  const handleConfirmLock = async () => {
    if (!currentCharacter) return;

    try {
      setLockingRelationship(true);

      // Call lock endpoint
      const response = await api.post(
        `/characters/${currentCharacter.id}/lock-relationship`,
        null,
        {
          params: {
            relationship_role: currentCharacter.relationship_role,
            user_role: currentCharacter.user_role,
          },
        }
      );

      if (response.data.success) {
        // Update character state to reflect lock
        setCurrentCharacter({
          ...currentCharacter,
          relationship_locked: true,
          relationship_locked_at: response.data.locked_at,
        });

        // Close modal
        setShowRelationshipLockModal(false);

        // Send pending message
        if (pendingMessage) {
          await sendMessage(pendingMessage);
          setPendingMessage(null);
        }
      }
    } catch (err: any) {
      console.error('Failed to lock relationship:', err);
      setError('Failed to lock relationship. Please try again.');
    } finally {
      setLockingRelationship(false);
    }
  };

  const handleCancelLock = () => {
    setShowRelationshipLockModal(false);
    setPendingMessage(null);
  };

  // PRD v3: Scene choice selection
  const handleSceneChoiceSelect = (choice: string) => {
    handleSendMessage(choice);
    clearSceneChoices();
  };

  return (
    <div className="relative z-20 flex h-full min-h-[100dvh] w-full flex-col overflow-hidden">
      {/* Top Bar */}
      <div className="bg-zinc-900 border-b border-white/10 px-2 sm:px-4 py-2 sm:py-3 flex items-center gap-2 sm:gap-4 flex-shrink-0">
        {/* Mobile Menu Button */}
        <button
          onClick={() => setIsMobileSidebarOpen(true)}
          className="text-zinc-400 hover:text-white"
        >
          <Menu size={24} />
        </button>

        {/* Home Button */}
        <button
          onClick={() => navigate('/')}
          className="text-zinc-400 hover:text-white"
          title="Back to Home"
        >
          <Home size={24} />
        </button>

        {/* Current Character Info */}
        {currentCharacter ? (
          <div className="flex items-center gap-2 sm:gap-3 flex-1 min-w-0">
            <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-gradient-primary flex items-center justify-center text-white font-semibold text-sm sm:text-base flex-shrink-0">
              {currentCharacter.first_name.charAt(0)}
            </div>
            <div className="flex-1 min-w-0">
              <h2 className="font-semibold text-white truncate text-sm sm:text-base">
                {currentCharacter.first_name}
              </h2>
              <div className="flex items-center gap-2">
                <p className="text-xs sm:text-sm text-zinc-400 truncate hidden sm:block">
                  {(currentCharacter.personality_tags || []).slice(0, 2).join(', ')}
                </p>
                <span className="hidden sm:inline text-[11px] px-2 py-0.5 rounded-full border border-zinc-700 text-zinc-300">
                  {relationshipStage}
                </span>
                {intimacy > 0 && (
                  <IntimacyMeterCompact value={intimacy} className="hidden sm:flex" />
                )}
              </div>
            </div>
          </div>
        ) : (
          <div className="flex-1 min-w-0">
            <p className="text-zinc-400 text-sm sm:text-base truncate">Select a character</p>
          </div>
        )}

        {/* Action Buttons */}
        <div className="flex items-center gap-1 sm:gap-2 flex-shrink-0">
          {/* Credits Display */}
          <div className="flex items-center gap-1 sm:gap-1.5 px-2 sm:px-3 py-1 sm:py-1.5 rounded-full bg-yellow-500/10 border border-yellow-500/20 text-yellow-500">
            <Coins size={14} className="sm:w-4 sm:h-4" />
            <span className="font-medium text-xs sm:text-sm">{user?.credits || 0}</span>
          </div>

          {currentCharacter && (
            <>
              {/* Gallery Button */}
              <Button
                variant="outline"
                size="sm"
                className="flex items-center gap-2 p-2 sm:px-3"
                onClick={() => setIsGalleryOpen(true)}
                title="Gallery"
              >
                <Image size={16} />
                <span className="hidden sm:inline">Gallery</span>
              </Button>
              <Button
                variant="outline"
                size="sm"
                className="flex items-center gap-2 p-2 sm:px-3"
                onClick={() => setShowConsentModal(true)}
                title="Explicit Consent"
              >
                <ShieldCheck size={16} />
                <span className="hidden sm:inline">Consent</span>
              </Button>
              {/* Video Button */}
              {/* <Button
                variant="outline"
                size="sm"
                onClick={() => setIsVoiceCallOpen(true)}
                disabled={!currentCharacter || isTyping}
                className="flex items-center gap-2 p-2 sm:px-3"
                title="Video Chat"
              >
                <Video size={16} />
                <span className="hidden sm:inline">Video</span>
              </Button> */}

            </>
          )}
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* Character Sidebar */}
        <CharacterSelector
          currentCharacterId={currentCharacter?.id}
          onSelectCharacter={handleSelectCharacter}
          isMobileOpen={isMobileSidebarOpen}
          onMobileClose={() => setIsMobileSidebarOpen(false)}
          disabled={isTyping}
        />

        {/* Mobile Sidebar Overlay */}
        {isMobileSidebarOpen && (
          <div
            onClick={() => setIsMobileSidebarOpen(false)}
            className="fixed inset-0 bg-black/50 z-30"
          />
        )}

        {/* Main Chat Area */}
        <div
          className="relative flex-1 flex flex-col overflow-hidden bg-zinc-950"
          style={chatBackdrop ? {
            backgroundImage: `url(${chatBackdrop})`,
            backgroundSize: 'contain',
            backgroundPosition: 'center center',
            backgroundRepeat: 'no-repeat',
          } : undefined}
        >
          {chatBackdrop && (
            <div className="absolute inset-0 bg-black/65" />
          )}
          {loadingCharacter || (currentCharacter && isSessionLoading) ? (
            <div className="flex-1 flex items-center justify-center">
              <div className="text-center space-y-4">
                <div className="w-16 h-16 border-4 border-primary-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
                <p className="text-zinc-400">
                  {loadingCharacter ? 'Loading character...' : 'Preparing chat...'}
                </p>
              </div>
            </div>
          ) : !currentCharacter ? (
            <div className="flex-1 flex items-center justify-center p-8">
              <div className="text-center space-y-6 max-w-md">
                <div className="w-20 h-20 bg-gradient-primary rounded-full flex items-center justify-center mx-auto">
                  <Sparkles size={32} className="text-white" />
                </div>
                <div className="space-y-2">
                  <h2 className="text-2xl font-heading font-bold text-white">
                    Welcome to AI Companion
                  </h2>
                  <p className="text-zinc-400">
                    Select a character from the sidebar to start chatting
                  </p>
                </div>
              </div>
            </div>
          ) : (
            <div className="relative z-10 flex-1 flex flex-col min-h-0">
              {/* Error Message */}
              {error && (
                <div className="mx-4 mt-4 p-3 rounded-lg bg-red-500/10 border border-red-500/50 flex items-start gap-2">
                  <AlertCircle size={20} className="text-red-500 flex-shrink-0 mt-0.5" />
                  <p className="text-red-500 text-sm">{error}</p>
                </div>
              )}

              {/* Scene Banner (script scene / recap) */}
              {sceneBanner && (
                <SceneBanner
                  scene={sceneBanner.scene}
                  synopsis={sceneBanner.synopsis}
                  characterName={currentCharacter.first_name}
                />
              )}

              {/* Messages */}
              <MessageList
                messages={messages}
                isTyping={isTyping}
                characterName={currentCharacter.first_name}
                sessionId={sessionId || undefined}
              />

              {/* PRD v3: Scene Choices (priority over regular suggestions) */}
              {sceneChoices && sceneChoices.choices.length > 0 && (
                <SceneChoices
                  choices={sceneChoices.choices}
                  onSelect={handleSceneChoiceSelect}
                  disabled={isTyping || isSessionLoading}
                  sceneInfo={sceneChoices.sceneState}
                />
              )}

              {/* Chat Input */}
              <ChatInput
                onSend={handleSendMessage}
                placeholder={`Message ${currentCharacter.first_name}...`}
              />
            </div>
          )}
        </div>
      </div>

      {/* Gallery Modal */}
      <GalleryModal
        isOpen={isGalleryOpen}
        onClose={() => setIsGalleryOpen(false)}
        characterId={currentCharacter?.id || ''}
        characterName={currentCharacter?.first_name || ''}
      />

      {/* Story Completion Modal */}
      {storyCompletedData && sessionId && (
        <StoryCompletionModal
          data={storyCompletedData}
          sessionId={sessionId}
          onClose={clearStoryCompletedData}
        />
      )}

      {/* PRD v2026.02: Relationship Lock Modal */}
      {currentCharacter && (
        <RelationshipLockModal
          isOpen={showRelationshipLockModal}
          onClose={handleCancelLock}
          onConfirm={handleConfirmLock}
          characterName={currentCharacter.first_name || 'Character'}
          characterRole={currentCharacter.relationship_role || 'Character'}
          userRole={currentCharacter.user_role || 'You'}
          isLoading={lockingRelationship}
        />
      )}

      {currentCharacter && (
        <ConsentModal
          isOpen={showConsentModal}
          characterId={currentCharacter.id}
          characterName={currentCharacter.first_name}
          onClose={() => setShowConsentModal(false)}
        />
      )}
    </div>
  );
}

