        <div className="mt-6 text-center text-sm text-zinc-500">
          <p>Didn't receive the email? Check your spam folder.</p>
        </div>
      </Container>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
