/**
 * Gallery Page - Display all user's generated media
 * Shows images and videos across all characters with filters
 */
import { useEffect, useState } from 'react';
import { Image as ImageIcon, Video, Filter, X, Download, Share2, Loader2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { api } from '@/services/api';
import { Button } from '@/components/common';

interface GalleryItem {
  id: string;
  image_url?: string;
  video_url?: string;
  created_at: string;
  content?: string;
  character_name?: string;
  character_id?: string;
  character_image_url?: string;
  session_id?: string;
}

type MediaType = 'all' | 'image' | 'video';
type SortBy = 'newest' | 'oldest' | 'character';

export function GalleryPage() {
  const navigate = useNavigate();
  const [items, setItems] = useState<GalleryItem[]>([]);
  const [filteredItems, setFilteredItems] = useState<GalleryItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [selectedItem, setSelectedItem] = useState<GalleryItem | null>(null);

  // Filters
  const [mediaType, setMediaType] = useState<MediaType>('all');
  const [sortBy, setSortBy] = useState<SortBy>('newest');
  const [characterFilter, setCharacterFilter] = useState<string>('all');
  const [showFilters, setShowFilters] = useState(false);

  // Character list for filter dropdown
  const [characters, setCharacters] = useState<{ id: string; name: string }[]>([]);

  useEffect(() => {
    fetchGallery();
  }, [mediaType]);

  useEffect(() => {
    applyFilters();
  }, [items, sortBy, characterFilter]);

  const fetchGallery = async () => {
    setLoading(true);
    try {
      const response = await api.get(`/chat/gallery`, {
        params: { media_type: mediaType, limit: 200 },
      });
      if (Array.isArray(response.data)) {
        setItems(response.data);

        // Extract unique characters
        const uniqueChars = new Map<string, string>();
        response.data.forEach((item: GalleryItem) => {
          if (item.character_id && item.character_name) {
            uniqueChars.set(item.character_id, item.character_name);
          }
        });
        setCharacters(
          Array.from(uniqueChars.entries()).map(([id, name]) => ({ id, name }))
        );
      } else {
        setItems([]);
      }
    } catch (error) {
      console.error('Failed to fetch gallery:', error);
    } finally {
      setLoading(false);
    }
  };

  const applyFilters = () => {
    let filtered = [...items];

    // Filter by character
    if (characterFilter !== 'all') {
      filtered = filtered.filter(item => item.character_id === characterFilter);
    }

    // Sort
    if (sortBy === 'newest') {
      filtered.sort((a, b) =>
        new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
      );
    } else if (sortBy === 'oldest') {
      filtered.sort((a, b) =>
        new Date(a.created_at).getTime() - new Date(b.created_at).getTime()
      );
    } else if (sortBy === 'character') {
      filtered.sort((a, b) =>
        (a.character_name || '').localeCompare(b.character_name || '')
      );
    }

    setFilteredItems(filtered);
  };

  const handleDownload = async (item: GalleryItem) => {
    const url = item.video_url || item.image_url;
    if (!url) return;

    try {
      const response = await fetch(url);
      const blob = await response.blob();
      const blobUrl = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = blobUrl;
      link.download = `${item.character_name || 'media'}-${item.id}.${
        item.video_url ? 'mp4' : 'png'
      }`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(blobUrl);
    } catch (error) {
      console.error('Download failed:', error);
    }
  };

  const handleShare = async (item: GalleryItem) => {
    const url = item.video_url || item.image_url;
    if (!url) return;

    if (navigator.share) {
      try {
        await navigator.share({
          title: `AI Generated by ${item.character_name}`,
          text: item.content || 'Check out this AI-generated media!',
          url: url,
        });
      } catch (error) {
        console.error('Share failed:', error);
      }
    } else {
      // Fallback: Copy URL to clipboard
      navigator.clipboard.writeText(url);
      alert('Link copied to clipboard!');
    }
  };

  return (
    <div className="min-h-screen bg-zinc-950 text-white">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-zinc-900/95 backdrop-blur-sm border-b border-zinc-800">
        <div className="container mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-heading font-bold">My Gallery</h1>
              <p className="text-sm text-zinc-400 mt-1">
                {filteredItems.length} {mediaType === 'all' ? 'items' : `${mediaType}s`}
              </p>
            </div>
            <Button
              variant="secondary"
              onClick={() => setShowFilters(!showFilters)}
              className="flex items-center gap-2"
            >
              <Filter size={16} />
              {showFilters ? 'Hide Filters' : 'Show Filters'}
            </Button>
          </div>

          {/* Filters */}
          {showFilters && (
            <div className="mt-4 p-4 bg-zinc-800/50 rounded-lg border border-zinc-700 grid grid-cols-1 sm:grid-cols-3 gap-4">
              {/* Media Type Filter */}
              <div>
                <label className="block text-sm font-medium text-zinc-300 mb-2">
                  Media Type
                </label>
                <select
                  value={mediaType}
                  onChange={(e) => setMediaType(e.target.value as MediaType)}
                  className="w-full bg-zinc-900 border border-zinc-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:ring-2 focus:ring-pink-500"
                >
                  <option value="all">All Media</option>
                  <option value="image">Images Only</option>
                  <option value="video">Videos Only</option>
                </select>
              </div>

              {/* Sort By */}
              <div>
                <label className="block text-sm font-medium text-zinc-300 mb-2">
                  Sort By
                </label>
                <select
                  value={sortBy}
                  onChange={(e) => setSortBy(e.target.value as SortBy)}
                  className="w-full bg-zinc-900 border border-zinc-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:ring-2 focus:ring-pink-500"
                >
                  <option value="newest">Newest First</option>
                  <option value="oldest">Oldest First</option>
                  <option value="character">By Character</option>
                </select>
              </div>

              {/* Character Filter */}
              <div>
                <label className="block text-sm font-medium text-zinc-300 mb-2">
                  Character
                </label>
                <select
                  value={characterFilter}
                  onChange={(e) => setCharacterFilter(e.target.value)}
                  className="w-full bg-zinc-900 border border-zinc-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:ring-2 focus:ring-pink-500"
                >
                  <option value="all">All Characters</option>
                  {characters.map((char) => (
                    <option key={char.id} value={char.id}>
                      {char.name}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          )}
        </div>
      </header>

      {/* Gallery Grid */}
      <main className="container mx-auto px-4 py-8">
        {loading ? (
          <div className="flex flex-col items-center justify-center h-64 text-zinc-400">
            <Loader2 size={48} className="animate-spin mb-4" />
            <p className="text-lg">Loading your gallery...</p>
          </div>
        ) : filteredItems.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-64 text-zinc-500">
            <ImageIcon size={64} className="mb-4 opacity-20" />
            <p className="text-xl mb-2">No media found</p>
            <p className="text-sm">
              {mediaType === 'all'
                ? 'Start chatting with your characters to generate images and videos!'
                : `No ${mediaType}s generated yet`}
            </p>
            <Button
              onClick={() => navigate('/chat')}
              className="mt-4"
            >
              Start Chatting
            </Button>
          </div>
        ) : (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
            {filteredItems.map((item) => (
              <div
                key={item.id}
                className="relative aspect-square rounded-lg overflow-hidden group cursor-pointer border border-zinc-800 bg-zinc-900 hover:border-pink-500 transition-all"
                onClick={() => setSelectedItem(item)}
              >
                {/* Media */}
                {item.video_url ? (
                  <div className="w-full h-full relative">
                    <video
                      src={item.video_url}
                      className="w-full h-full object-cover"
                      muted
                      onMouseOver={(e) => e.currentTarget.play()}
                      onMouseOut={(e) => e.currentTarget.pause()}
                    />
                    <div className="absolute top-2 right-2 bg-black/60 p-1.5 rounded-md">
                      <Video size={14} className="text-white" />
                    </div>
                  </div>
                ) : (
                  <img
                    src={item.image_url}
                    alt="Generated content"
                    className="w-full h-full object-cover transition-transform group-hover:scale-105"
                  />
                )}

                {/* Overlay with character info */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex flex-col justify-end p-3">
                  {item.character_name && (
                    <div className="flex items-center gap-2 mb-2">
                      {item.character_image_url && (
                        <img
                          src={item.character_image_url}
                          alt={item.character_name}
                          className="w-6 h-6 rounded-full border border-white/20"
                        />
                      )}
                      <p className="text-xs font-semibold text-white truncate">
                        {item.character_name}
                      </p>
                    </div>
                  )}
                  <p className="text-xs text-zinc-300">
                    {new Date(item.created_at).toLocaleDateString()}
                  </p>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>

      {/* Full Screen Preview Modal */}
      {selectedItem && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 p-4 animate-in fade-in duration-200"
          onClick={() => setSelectedItem(null)}
        >
          {/* Close button */}
          <button
            className="absolute top-4 right-4 p-2 text-white/70 hover:text-white bg-black/50 rounded-full transition-colors"
            onClick={() => setSelectedItem(null)}
            aria-label="Close preview"
          >
            <X size={24} />
          </button>

          {/* Action buttons */}
          <div className="absolute top-4 left-4 flex gap-2">
            <button
              className="p-2 text-white/70 hover:text-white bg-black/50 rounded-full transition-colors"
              onClick={(e) => {
                e.stopPropagation();
                handleDownload(selectedItem);
              }}
              aria-label="Download"
            >
              <Download size={20} />
            </button>
            <button
              className="p-2 text-white/70 hover:text-white bg-black/50 rounded-full transition-colors"
              onClick={(e) => {
                e.stopPropagation();
                handleShare(selectedItem);
              }}
              aria-label="Share"
            >
              <Share2 size={20} />
            </button>
          </div>

          {/* Character info */}
          {selectedItem.character_name && (
            <div className="absolute bottom-4 left-4 flex items-center gap-3 bg-black/50 backdrop-blur-sm rounded-lg p-3">
              {selectedItem.character_image_url && (
                <img
                  src={selectedItem.character_image_url}
                  alt={selectedItem.character_name}
                  className="w-10 h-10 rounded-full border-2 border-white/20"
                />
              )}
              <div>
                <p className="text-sm font-semibold text-white">
                  {selectedItem.character_name}
                </p>
                <p className="text-xs text-zinc-400">
                  {new Date(selectedItem.created_at).toLocaleString()}
                </p>
              </div>
            </div>
          )}

          {/* Media */}
          <div className="max-w-full max-h-full" onClick={(e) => e.stopPropagation()}>
            {selectedItem.video_url ? (
              <video
                src={selectedItem.video_url}
                controls
                autoPlay
                className="max-w-full max-h-[90vh] rounded-lg shadow-2xl"
              />
            ) : (
              <img
                src={selectedItem.image_url}
                alt="Full view"
                className="max-w-full max-h-[90vh] rounded-lg shadow-2xl"
              />
            )}
          </div>
        </div>
      )}
    </div>
  );
}

import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Link, useNavigate, Navigate } from 'react-router-dom';
import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { Button, Input, Card } from '@/components/common';
import { Container } from '@/components/layout';
import { Sparkles, ShieldCheck } from 'lucide-react';

const loginSchema = z.object({
  email: z.string().email('Invalid email address'),
  password: z.string().min(6, 'Password must be at least 6 characters'),
});

type LoginFormData = z.infer<typeof loginSchema>;

export function LoginPage() {
  const navigate = useNavigate();
  const { login, loginWithGoogle, isAuthenticated, loading: authLoading } = useAuth();
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [googleLoading, setGoogleLoading] = useState(false);

  // Redirect to chat if already authenticated
  if (!authLoading && isAuthenticated) {
    return <Navigate to="/chat" replace />;
  }

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<LoginFormData>({
    resolver: zodResolver(loginSchema),
  });

  const onSubmit = async (data: LoginFormData) => {
    setError('');
    setLoading(true);

    try {
      await login(data.email, data.password);
      navigate('/chat');
    } catch (err: any) {
      console.error('Login error:', err);
      if (err.code === 'auth/user-not-found') {
        setError('No account found with this email');
      } else if (err.code === 'auth/wrong-password') {
        setError('Incorrect password');
      } else if (err.code === 'auth/invalid-credential') {
        setError('Invalid email or password');
      } else {
        setError('Failed to login. Please try again.');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError('');
    setGoogleLoading(true);

    try {
      await loginWithGoogle();
      navigate('/chat');
    } catch (err: any) {
      console.error('Google login error:', err);
      if (err.code === 'auth/popup-closed-by-user') {
        // User closed the popup, no error to show
      } else if (err.code === 'auth/cancelled-popup-request') {
        // Duplicate popup request, ignore
      } else {
        setError('Failed to sign in with Google. Please try again.');
      }
    } finally {
      setGoogleLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center py-12 px-4">
      <Container size="sm">
        <div className="text-center mb-8">
          <div className="flex justify-center mb-4">
            <div className="relative">
              <div className="w-16 h-16 bg-gradient-primary rounded-2xl flex items-center justify-center">
                <Sparkles size={32} className="text-white" />
              </div>
              <div className="absolute inset-0 bg-gradient-primary rounded-2xl blur-xl opacity-50"></div>
            </div>
          </div>
          <h1 className="text-4xl font-heading font-bold mb-2">
            Welcome Back
          </h1>
          <p className="text-zinc-400">
            Sign in to continue your AI companion journey
          </p>
        </div>

        <Card glass>
          <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
            {error && (
              <div className="bg-red-500/10 border border-red-500/50 text-red-500 px-4 py-3 rounded-lg text-sm">
                {error}
              </div>
            )}

            <div>
              <Input
                {...register('email')}
                type="email"
                label="Email"
                placeholder="your@email.com"
                error={errors.email?.message}
                disabled={loading}
                autoComplete="email"
              />
            </div>

            <div>
              <Input
                {...register('password')}
                type="password"
                label="Password"
                placeholder="••••••••"
                error={errors.password?.message}
                disabled={loading}
                autoComplete="current-password"
              />
            </div>

            <div className="flex items-center justify-between text-sm">
              <label className="flex items-center gap-2 cursor-pointer">
                <input
                  type="checkbox"
                  className="w-4 h-4 rounded border-white/20 bg-white/5 text-primary-500 focus:ring-primary-500 focus:ring-offset-0"
                />
                <span className="text-zinc-400">Remember me</span>
              </label>
              <Link
                to="/forgot-password"
                className="text-primary-500 hover:text-primary-400 transition-colors"
              >
                Forgot password?
              </Link>
            </div>

            <Button
              type="submit"
              variant="primary"
              className="w-full"
              loading={loading}
              disabled={loading || googleLoading}
            >
              Sign In
            </Button>

            <div className="relative">
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-white/10"></div>
              </div>
              <div className="relative flex justify-center text-sm">
                <span className="px-2 bg-zinc-900 text-zinc-400">or</span>
              </div>
            </div>

            <Button
              type="button"
              variant="secondary"
              className="w-full flex items-center justify-center gap-3"
              onClick={handleGoogleLogin}
              loading={googleLoading}
              disabled={loading || googleLoading}
            >
              <svg className="w-5 h-5" viewBox="0 0 24 24">
                <path
                  fill="currentColor"
                  d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                />
                <path
                  fill="currentColor"
                  d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                />
                <path
                  fill="currentColor"
                  d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                />
                <path
                  fill="currentColor"
                  d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                />
              </svg>
              Continue with Google
            </Button>

            {/* Age Notice */}
            <div className="space-y-3 pt-2">
              <div className="flex items-start gap-2 text-amber-500/90 bg-amber-500/10 p-3 rounded-lg text-xs leading-relaxed">
                <ShieldCheck className="shrink-0 w-4 h-4 mt-0.5" />
                <p>
                  <span className="font-medium">18+ Only:</span> By signing in, you confirm that you are at least 18 years old.
                </p>
              </div>
            </div>

            <div className="text-center text-sm text-zinc-400">
              Don't have an account?{' '}
              <Link
                to="/register"
                className="text-primary-500 hover:text-primary-400 transition-colors font-medium"
              >
                Create one
              </Link>
            </div>
          </form>
        </Card>
      </Container>
    </div>
  );
}

/**
 * Memory Management Page
 * PRD v3 Section 8.3 - User-facing memory management UI
 */

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Loader2, Brain, FileText, Heart, ArrowLeft } from 'lucide-react';
import { MainLayout } from '@/components/layout';
import { Container } from '@/components/layout/Container';
import { FactsList, EpisodesList, BondsList } from '@/components/memory/MemoryList';
import {
  getCharacterMemories,
  forgetFact,
  correctFact,
  type MemoryResponse,
} from '@/services/memoryService';
import { Button } from '@/components/ui/button';

type TabType = 'facts' | 'episodes' | 'bonds';

export function MemoryManagementPage() {
  const { characterId } = useParams<{ characterId: string }>();
  const navigate = useNavigate();

  const [memories, setMemories] = useState<MemoryResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedTab, setSelectedTab] = useState<TabType>('facts');

  useEffect(() => {
    if (characterId) {
      loadMemories();
    }
  }, [characterId]);

  const loadMemories = async () => {
    if (!characterId) return;

    setLoading(true);
    setError(null);

    try {
      const data = await getCharacterMemories(characterId);
      setMemories(data);
    } catch (err: unknown) {
      console.error('Failed to load memories:', err);
      setError('Failed to load memories. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleForgetFact = async (factContent: string) => {
    if (!characterId) return;

    try {
      await forgetFact(characterId, factContent);
      // Reload memories after deletion
      await loadMemories();
    } catch (err: unknown) {
      console.error('Failed to forget fact:', err);
      alert('Failed to delete fact. Please try again.');
      throw err;
    }
  };

  const handleCorrectFact = async (
    oldContent: string,
    newContent: string,
    category?: string
  ) => {
    if (!characterId) return;

    try {
      await correctFact(characterId, oldContent, newContent, category);
      // Reload memories after update
      await loadMemories();
    } catch (err: unknown) {
      console.error('Failed to correct fact:', err);
      alert('Failed to update fact. Please try again.');
      throw err;
    }
  };

  const tabs = [
    { id: 'facts' as TabType, label: 'Facts', icon: Brain, count: memories?.facts.length || 0 },
    {
      id: 'episodes' as TabType,
      label: 'Episodes',
      icon: FileText,
      count: memories?.episodes.length || 0,
    },
    { id: 'bonds' as TabType, label: 'Bonds', icon: Heart, count: memories?.bonds.length || 0 },
  ];

  return (
    <MainLayout>
      <Container className="py-8">
        {/* Header */}
        <div className="mb-8">
          <Button
            variant="ghost"
            onClick={() => navigate(-1)}
            className="mb-4 text-gray-400 hover:text-white"
          >
            <ArrowLeft className="mr-2 h-4 w-4" />
            Back
          </Button>

          <h1 className="mb-2 text-3xl font-bold text-white">Memory Management</h1>
          <p className="text-gray-400">
            View and manage what your AI companion remembers about you
          </p>
        </div>

        {/* Loading State */}
        {loading && (
          <div className="flex min-h-[400px] items-center justify-center">
            <div className="text-center">
              <Loader2 className="mx-auto h-12 w-12 animate-spin text-pink-500" />
              <p className="mt-4 text-gray-400">Loading memories...</p>
            </div>
          </div>
        )}

        {/* Error State */}
        {error && !loading && (
          <div className="rounded-lg border border-red-900 bg-red-950/20 p-6">
            <p className="text-red-400">{error}</p>
            <Button onClick={loadMemories} className="mt-4">
              Try Again
            </Button>
          </div>
        )}

        {/* Content */}
        {!loading && !error && memories && (
          <>
            {/* Tab Navigation */}
            <div className="mb-6 flex space-x-2 border-b border-zinc-800">
              {tabs.map((tab) => {
                const Icon = tab.icon;
                return (
                  <button
                    key={tab.id}
                    onClick={() => setSelectedTab(tab.id)}
                    className={`flex items-center space-x-2 border-b-2 px-4 py-3 text-sm font-medium transition-colors ${
                      selectedTab === tab.id
                        ? 'border-pink-500 text-pink-500'
                        : 'border-transparent text-gray-400 hover:text-gray-300'
                    }`}
                  >
                    <Icon className="h-4 w-4" />
                    <span>{tab.label}</span>
                    <span
                      className={`rounded-full px-2 py-0.5 text-xs ${
                        selectedTab === tab.id
                          ? 'bg-pink-500/20 text-pink-400'
                          : 'bg-zinc-800 text-gray-400'
                      }`}
                    >
                      {tab.count}
                    </span>
                  </button>
                );
              })}
            </div>

            {/* Tab Content */}
            <div className="min-h-[400px]">
              {selectedTab === 'facts' && (
                <FactsList
                  facts={memories.facts}
                  onForget={handleForgetFact}
                  onCorrect={handleCorrectFact}
                />
              )}

              {selectedTab === 'episodes' && <EpisodesList episodes={memories.episodes} />}

              {selectedTab === 'bonds' && <BondsList bonds={memories.bonds} />}
            </div>

            {/* Session Summary */}
            {memories.session_summary && (
              <div className="mt-8 rounded-lg border border-zinc-800 bg-zinc-900 p-6">
                <h3 className="mb-3 text-lg font-semibold text-white">Session Summary</h3>
                <p className="text-gray-300">{memories.session_summary}</p>
              </div>
            )}
          </>
        )}
      </Container>
    </MainLayout>
  );
}

import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Link, useNavigate, Navigate } from 'react-router-dom';
import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { Button, Input, Card } from '@/components/common';
import { Container } from '@/components/layout';
import { Sparkles, AlertTriangle } from 'lucide-react';
import { useRecaptcha } from '@/hooks/useRecaptcha';

const registerSchema = z.object({
  email: z.string().email('Invalid email address'),
  password: z.string().min(6, 'Password must be at least 6 characters'),
  confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
  message: "Passwords don't match",
  path: ['confirmPassword'],
});

type RegisterFormData = z.infer<typeof registerSchema>;

export function RegisterPage() {
  const navigate = useNavigate();
  const { register: registerUser, loginWithGoogle, isAuthenticated, loading: authLoading } = useAuth();
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [googleLoading, setGoogleLoading] = useState(false);
  const { executeRecaptcha } = useRecaptcha();

  // Redirect to chat if already authenticated
  if (!authLoading && isAuthenticated) {
    return <Navigate to="/chat" replace />;
  }

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<RegisterFormData>({
    resolver: zodResolver(registerSchema),
  });

  const onSubmit = async (data: RegisterFormData) => {
    setError('');
    setLoading(true);

    try {
      // Execute reCAPTCHA before registration
      const captchaToken = await executeRecaptcha('register');

      await registerUser(data.email, data.password, captchaToken);
      // Navigate to check email page instead of create-character
      navigate('/register/check-email', { state: { email: data.email } });
    } catch (err: any) {
      console.error('Registration error:', err);
      if (err.response?.status === 429) {
        setError('Too many attempts. Please try again later.');
      } else if (err.response?.data?.detail) {
        setError(err.response.data.detail);
      } else if (err.code === 'auth/email-already-in-use') {
        setError('An account with this email already exists');
      } else if (err.code === 'auth/weak-password') {
        setError('Password is too weak. Please use a stronger password.');
      } else {
        setError('Failed to send verification email. Please try again.');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSignUp = async () => {
    setError('');
    setGoogleLoading(true);

    try {
      // Google OAuth flow - DOB will be collected after if needed
      await loginWithGoogle();
      navigate('/chat');
    } catch (err: any) {
      console.error('Google sign-up error:', err);
      if (err.code === 'auth/popup-closed-by-user') {
        // User closed the popup, no error to show
      } else if (err.code === 'auth/cancelled-popup-request') {
        // Duplicate popup request, ignore
      } else if (err.needsDOB) {
        // New user needs to provide DOB - handled by modal
        navigate('/chat', { state: { needsDOB: true } });
      } else {
        setError('Failed to sign up with Google. Please try again.');
      }
    } finally {
      setGoogleLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center py-12 px-4">
      <Container size="sm">
        <div className="text-center mb-8">
          <div className="flex justify-center mb-4">
            <div className="relative">
              <div className="w-16 h-16 bg-gradient-primary rounded-2xl flex items-center justify-center">
                <Sparkles size={32} className="text-white" />
              </div>
              <div className="absolute inset-0 bg-gradient-primary rounded-2xl blur-xl opacity-50"></div>
            </div>
          </div>
          <h1 className="text-4xl font-heading font-bold mb-2">
            Create Account
          </h1>
          <p className="text-zinc-400">
            Start your journey with AI companionship
          </p>
        </div>

        <Card glass>
          <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
            {error && (
              <div className="bg-red-500/10 border border-red-500/50 text-red-500 px-4 py-3 rounded-lg text-sm">
                {error}
              </div>
            )}

            <div>
              <Input
                {...register('email')}
                type="email"
                label="Email"
                placeholder="your@email.com"
                error={errors.email?.message}
                disabled={loading}
                autoComplete="email"
              />
            </div>

            <div>
              <Input
                {...register('password')}
                type="password"
                label="Password"
                placeholder="••••••••"
                error={errors.password?.message}
                disabled={loading}
                autoComplete="new-password"
                helperText="Must be at least 6 characters"
              />
            </div>

            <div>
              <Input
                {...register('confirmPassword')}
                type="password"
                label="Confirm Password"
                placeholder="••••••••"
                error={errors.confirmPassword?.message}
                disabled={loading}
                autoComplete="new-password"
              />
            </div>

            <div className="space-y-4 pt-2 border-t border-white/10">
              {/* Age Verification */}
              <div className="flex items-start gap-3 text-amber-500/90 bg-amber-500/10 p-3 rounded-lg text-xs leading-relaxed">
                <AlertTriangle className="shrink-0 w-4 h-4 mt-0.5" />
                <p>
                  <span className="font-medium">18+ Only:</span> This website contains age-restricted materials. You must be 18 or older to create an account.
                </p>
              </div>
            </div>

            <div className="text-sm text-zinc-400">
              By creating an account, you agree to our{' '}
              <Link to="/terms" className="text-primary-500 hover:text-primary-400">
                Terms of Service
              </Link>{' '}
              and{' '}
              <Link to="/privacy" className="text-primary-500 hover:text-primary-400">
                Privacy Policy
              </Link>
            </div>

            <Button
              type="submit"
              variant="primary"
              className="w-full"
              loading={loading}
              disabled={loading || googleLoading}
            >
              Create Account
            </Button>

            <div className="relative">
              <div className="absolute inset-0 flex items-center">
