import { useEffect, useState, useRef } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { signInWithCustomToken } from 'firebase/auth';
import { auth } from '@/config/firebase';
import { authService } from '@/services/authService';
import { Loader2, CheckCircle, XCircle } from 'lucide-react';
import { Card } from '@/components/common/Card';
import { Container } from '@/components/layout/Container';

export function VerifyEmailPage() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [status, setStatus] = useState<'verifying' | 'success' | 'error'>('verifying');
  const [errorMessage, setErrorMessage] = useState('');
  const verifiedRef = useRef(false);

  useEffect(() => {
    const verifyEmail = async () => {
      const token = searchParams.get('token');

      if (!token) {
        setStatus('error');
        setErrorMessage('Invalid verification link');
        return;
      }

      // Prevent double execution in strict mode
      if (verifiedRef.current) return;
      verifiedRef.current = true;

      try {
        // Call backend to verify token and create account
        const { customToken } = await authService.verifyEmail(token);

        // Sign in with custom token
        try {
          await signInWithCustomToken(auth, customToken);
        } catch (authError: any) {
          console.error('Firebase Auth Error:', authError);
          // If custom token login fails, but backend verification succeeded,
          // it might mean we are already verified or there is a config mismatch.
          // Since backend returned success, the user is likely created.
          // We can try to redirect to login page instead of showing failure.

          // Check if error is related to network or config
          if (authError.code === 'auth/network-request-failed') {
             setErrorMessage('Verification successful, but failed to log in automatically. Please log in manually.');
          } else {
             // Fallback: Assume success on backend means account is ready.
             console.warn("Ignoring Firebase login error after successful backend verification");
          }
        }

        setStatus('success');

        // Redirect to chat after 2 seconds
        setTimeout(() => {
          navigate('/chat');
        }, 2000);

      } catch (error: any) {
        console.error('Verification error:', error);
        setStatus('error');

        if (error.response?.data?.detail) {
          setErrorMessage(error.response.data.detail);
        } else {
          setErrorMessage('Failed to verify email. The link may be expired or invalid.');
        }
      }
    };

    verifyEmail();
  }, [searchParams, navigate]);

  return (
    <div className="min-h-screen flex items-center justify-center py-12 px-4 bg-gradient-to-br from-zinc-900 via-purple-900/20 to-zinc-900">
      <Container size="sm">
        <Card>
          <div className="text-center space-y-6 p-8">
            {status === 'verifying' && (
              <>
                <Loader2 size={64} className="mx-auto text-purple-500 animate-spin" />
                <h2 className="text-2xl font-bold text-white">Verifying Your Email...</h2>
                <p className="text-zinc-400">Please wait while we set up your account.</p>
              </>
            )}

            {status === 'success' && (
              <>
                <CheckCircle size={64} className="mx-auto text-green-500" />
                <h2 className="text-2xl font-bold text-green-400">Email Verified!</h2>
                <p className="text-zinc-400">
                  Your account has been created successfully.
                  <br />
                  Redirecting you to chat...
                </p>
              </>
            )}

            {status === 'error' && (
              <>
                <XCircle size={64} className="mx-auto text-red-500" />
                <h2 className="text-2xl font-bold text-red-400">Verification Failed</h2>
                <p className="text-zinc-400">{errorMessage}</p>
                <button
                  onClick={() => navigate('/register')}
                  className="text-purple-400 hover:text-purple-300 font-medium transition-colors"
                >
                  Back to Registration
                </button>
              </>
            )}
          </div>
        </Card>
      </Container>
    </div>
  );
}

/**
 * BlogList Page
 *
 * Public page displaying a grid of published blog posts.
 */

import React, { useState, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { getBlogPosts, type BlogPost } from '@/services/blogService';
import { Container } from '@/components/layout/Container';

export const BlogList: React.FC = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);

  const selectedTag = searchParams.get('tag') || undefined;

  useEffect(() => {
    loadPosts();
  }, [page, selectedTag]);

  const loadPosts = async () => {
    try {
      setLoading(true);
      setError(null);
      const response = await getBlogPosts(page, 12, selectedTag);
      setPosts(response.posts);
      setTotalPages(response.total_pages);
    } catch (err: any) {
      console.error('Failed to load blog posts:', err);
      setError(err.response?.data?.detail || 'Failed to load blog posts');
    } finally {
      setLoading(false);
    }
  };

  const handleTagClick = (tag: string) => {
    setSearchParams({ tag });
    setPage(1);
  };

  const clearTagFilter = () => {
    setSearchParams({});
    setPage(1);
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <Container className="py-12">
        {/* Header */}
        <div className="mb-12 text-center">
          <h1 className="text-4xl md:text-5xl font-bold text-gray-900 mb-4">
            Blog
          </h1>
        <p className="text-lg text-gray-600 max-w-2xl mx-auto">
          Insights, updates, and stories from the AIGirl team.
        </p>
      </div>

      {/* Tag Filter */}
      {selectedTag && (
        <div className="mb-8 flex items-center justify-center gap-2">
          <span className="text-sm text-gray-600">Filtering by tag:</span>
          <span className="px-3 py-1 bg-pink-100 text-pink-700 rounded-full text-sm font-medium">
            {selectedTag}
          </span>
          <button
            onClick={clearTagFilter}
            className="text-sm text-gray-500 hover:text-gray-700 underline"
          >
            Clear filter
          </button>
        </div>
      )}

      {/* Loading State */}
      {loading && (
        <div className="text-center py-12">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-pink-600"></div>
          <p className="mt-4 text-gray-600">Loading posts...</p>
        </div>
      )}

      {/* Error State */}
      {error && (
        <div className="bg-red-50 border border-red-200 rounded-lg p-4 text-center">
          <p className="text-red-700">{error}</p>
          <button
            onClick={loadPosts}
            className="mt-2 text-red-600 hover:text-red-700 underline"
          >
            Try again
          </button>
        </div>
      )}

      {/* Posts Grid */}
      {!loading && !error && posts.length === 0 && (
        <div className="text-center py-12">
          <p className="text-gray-600">No blog posts found.</p>
        </div>
      )}

      {!loading && !error && posts.length > 0 && (
        <>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {posts.map((post) => (
              <article
                key={post.id}
                onClick={() => navigate(`/blog/${post.slug}`)}
                className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition-shadow cursor-pointer"
              >
                {/* Cover Image */}
                {post.cover_image && (
                  <div className="h-48 overflow-hidden bg-gray-200">
                    <img
                      src={post.cover_image}
                      alt={post.title}
                      className="w-full h-full object-cover hover:scale-105 transition-transform duration-300"
                    />
                  </div>
                )}

                {/* Content */}
                <div className="p-6">
                  <h2 className="text-xl font-bold text-gray-900 mb-2 line-clamp-2">
                    {post.title}
                  </h2>

                  <p className="text-gray-600 text-sm mb-4 line-clamp-3">
                    {post.summary}
                  </p>

                  {/* Tags */}
                  {post.tags.length > 0 && (
                    <div className="flex flex-wrap gap-2 mb-4">
                      {post.tags.map((tag) => (
                        <button
                          key={tag}
                          onClick={(e) => {
                            e.stopPropagation();
                            handleTagClick(tag);
                          }}
                          className="px-2 py-1 bg-gray-100 text-gray-700 rounded text-xs font-medium hover:bg-pink-100 hover:text-pink-700 transition-colors"
                        >
                          {tag}
                        </button>
                      ))}
                    </div>
                  )}

                  {/* Meta */}
                  <div className="flex items-center justify-between text-xs text-gray-500">
                    <span>{formatDate(post.created_at)}</span>
                    <span>{post.views} views</span>
                  </div>
                </div>
              </article>
            ))}
          </div>

          {/* Pagination */}
          {totalPages > 1 && (
            <div className="flex justify-center items-center gap-2 mt-12">
              <button
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                disabled={page === 1}
                className="px-4 py-2 bg-white border border-gray-300 rounded-lg text-gray-700 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 transition-colors"
              >
                Previous
              </button>

              <span className="px-4 py-2 text-gray-700">
                Page {page} of {totalPages}
              </span>

              <button
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                disabled={page === totalPages}
                className="px-4 py-2 bg-white border border-gray-300 rounded-lg text-gray-700 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 transition-colors"
              >
                Next
              </button>
            </div>
          )}
        </>
      )}
      </Container>
    </div>
  );
};

