/**
 * Notification Service
 *
 * Provides a global SSE connection for receiving async notifications
 * such as video generation completion, credit updates, etc.
 *
 * This service should be initialized once on app startup and maintained
 * throughout the user's session.
 *
 * Usage:
 *   // In App.tsx or a top-level provider
 *   useEffect(() => {
 *     if (isAuthenticated) {
 *       notificationService.connect();
 *       notificationService.on('video_completed', handleVideoComplete);
 *     }
 *     return () => notificationService.disconnect();
 *   }, [isAuthenticated]);
 */

import { auth } from '@/config/firebase';

// ==================== Notification Event Types ====================

export type NotificationEventType =
  | 'video_completed'
  | 'video_failed'
  | 'credit_update'
  | 'heartbeat'
  | 'error';

export interface VideoCompletedNotification {
  task_id: string;
  session_id: string;
  message_id: string;
  video_url: string;
}

export interface VideoFailedNotification {
  task_id: string;
  session_id: string;
  error: string;
  error_code?: string;
}

export interface CreditUpdateNotification {
  balance: number;
  deducted: number;
  operation?: string;
}

export interface HeartbeatNotification {
  timestamp: string;
}

export interface ErrorNotification {
  message: string;
  error_code?: string;
}

export type NotificationPayload = {
  video_completed: VideoCompletedNotification;
  video_failed: VideoFailedNotification;
  credit_update: CreditUpdateNotification;
  heartbeat: HeartbeatNotification;
  error: ErrorNotification;
};

type NotificationHandler<T extends NotificationEventType> = (
  data: NotificationPayload[T]
) => void;

// ==================== Connection States ====================

export type ConnectionState = 'disconnected' | 'connecting' | 'connected' | 'reconnecting';

// ==================== Notification Service ====================

class NotificationService {
  private baseUrl: string;
  private abortController: AbortController | null = null;
  private handlers: Map<NotificationEventType, Set<NotificationHandler<any>>> = new Map();
  private connectionState: ConnectionState = 'disconnected';
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 10;
  private reconnectDelay = 1000; // Start with 1 second
  private maxReconnectDelay = 30000; // Max 30 seconds
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
  private stateChangeHandlers: Set<(state: ConnectionState) => void> = new Set();

  constructor() {
    this.baseUrl = import.meta.env.VITE_API_BASE_URL || '/api';
  }

  /**
   * Get the current connection state.
   */
  getConnectionState(): ConnectionState {
    return this.connectionState;
  }

  /**
   * Subscribe to connection state changes.
   */
  onStateChange(handler: (state: ConnectionState) => void): () => void {
    this.stateChangeHandlers.add(handler);
    return () => this.stateChangeHandlers.delete(handler);
  }

  private setConnectionState(state: ConnectionState): void {
    if (this.connectionState !== state) {
      this.connectionState = state;
      this.stateChangeHandlers.forEach((handler) => handler(state));
    }
  }

  /**
   * Get the current Firebase auth token.
   */
  private async getAuthToken(): Promise<string> {
    const user = auth.currentUser;
    if (!user) {
      throw new Error('User not authenticated');
    }
    return user.getIdToken();
  }

  /**
   * Parse SSE events from text.
   */
  private *parseSSE(text: string): Generator<{ type: NotificationEventType; data: any }> {
    const lines = text.split('\n');
    let currentEventType: string | null = null;
    let currentData: string | null = null;

    for (const line of lines) {
      if (line.startsWith('event: ')) {
        currentEventType = line.slice(7).trim();
      } else if (line.startsWith('data: ')) {
        currentData = line.slice(6);
      } else if (line === '' && currentEventType && currentData) {
        try {
          const parsed = JSON.parse(currentData);
          yield {
            type: currentEventType as NotificationEventType,
            data: parsed,
          };
        } catch (e) {
          console.warn('Failed to parse notification data:', currentData);
        }
        currentEventType = null;
        currentData = null;
      }
    }
  }

  /**
   * Emit an event to all registered handlers.
   */
  private emit<T extends NotificationEventType>(type: T, data: NotificationPayload[T]): void {
    const handlers = this.handlers.get(type);
    if (handlers) {
      handlers.forEach((handler) => {
        try {
          handler(data);
        } catch (e) {
          console.error(`Error in notification handler for ${type}:`, e);
        }
      });
    }
  }

  /**
   * Register a handler for a notification type.
   * Returns an unsubscribe function.
   */
  on<T extends NotificationEventType>(
    type: T,
    handler: NotificationHandler<T>
  ): () => void {
    if (!this.handlers.has(type)) {
      this.handlers.set(type, new Set());
    }
    this.handlers.get(type)!.add(handler);

    return () => {
      const handlers = this.handlers.get(type);
      if (handlers) {
        handlers.delete(handler);
      }
    };
  }

  /**
   * Remove all handlers for a notification type.
   */
  off(type: NotificationEventType): void {
    this.handlers.delete(type);
  }

  /**
   * Start the notification connection.
   */
  async connect(): Promise<void> {
    if (this.connectionState === 'connected' || this.connectionState === 'connecting') {
      return;
    }

    this.setConnectionState('connecting');

    try {
      await this.startStream();
    } catch (error) {
      console.error('Failed to connect notification service:', error);
      this.scheduleReconnect();
    }
  }

  /**
   * Start the SSE stream.
   */
  private async startStream(): Promise<void> {
    // Clean up any existing connection
    this.abort();

    this.abortController = new AbortController();
    const { signal } = this.abortController;

    try {
      const token = await this.getAuthToken();

      const response = await fetch(`${this.baseUrl}/notifications/stream`, {
        method: 'GET',
        headers: {
          Authorization: `Bearer ${token}`,
          Accept: 'text/event-stream',
          'Cache-Control': 'no-cache',
        },
        signal,
      });

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      this.setConnectionState('connected');
      this.reconnectAttempts = 0;
      this.reconnectDelay = 1000;

      const reader = response.body?.getReader();
      if (!reader) {
        throw new Error('No response body');
      }

      const decoder = new TextDecoder();
      let buffer = '';

      while (true) {
        const { done, value } = await reader.read();

        if (done) {
          console.log('Notification stream ended');
          break;
        }

        buffer += decoder.decode(value, { stream: true });

        // Process complete events
        const parts = buffer.split('\n\n');
        buffer = parts.pop() || '';

        for (const part of parts) {
          if (part.trim()) {
            for (const event of this.parseSSE(part + '\n\n')) {
              this.emit(event.type, event.data);
            }
          }
        }
      }
    } catch (error: any) {
      if (error.name === 'AbortError') {
        console.log('Notification stream aborted');
        return;
      }
      throw error;
    } finally {
      this.abortController = null;

      // If we were connected and the stream ended, try to reconnect
      if (this.connectionState === 'connected') {
        this.setConnectionState('disconnected');
        this.scheduleReconnect();
      }
    }
  }

  /**
   * Schedule a reconnection attempt with exponential backoff.
   */
  private scheduleReconnect(): void {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
    }

    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      console.error('Max reconnection attempts reached');
      this.setConnectionState('disconnected');
      this.emit('error', {
        message: 'Failed to connect to notification service after multiple attempts',
        error_code: 'max_reconnect_attempts',
      });
      return;
    }

    this.setConnectionState('reconnecting');
    this.reconnectAttempts++;

    const delay = Math.min(
      this.reconnectDelay * Math.pow(2, this.reconnectAttempts - 1),
      this.maxReconnectDelay
    );

    console.log(
      `Scheduling reconnection attempt ${this.reconnectAttempts} in ${delay}ms`
    );

    this.reconnectTimer = setTimeout(async () => {
      try {
        await this.startStream();
      } catch (error) {
        console.error('Reconnection failed:', error);
        this.scheduleReconnect();
      }
    }, delay);
  }

  /**
   * Abort the current connection.
   */
  private abort(): void {
    if (this.abortController) {
      this.abortController.abort();
      this.abortController = null;
    }
  }

  /**
   * Disconnect from the notification service.
   */
  disconnect(): void {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }

    this.abort();
    this.reconnectAttempts = 0;
    this.setConnectionState('disconnected');
  }

  /**
   * Check if the service is connected.
   */
  isConnected(): boolean {
    return this.connectionState === 'connected';
  }
}

// Export singleton instance
export const notificationService = new NotificationService();

﻿/**
 * Pipeline Service - Event pipeline service
 * 
 * v3.1 features:
 * - SSE event subscription
 * - Multimodal generation
 * - WebSocket real-time communication
 */

import { api } from './api';

// Event types
export type EventType =
  | 'chat.message.received'
  | 'chat.response.generated'
  | 'chat.response.streaming'
  | 'media.generation.started'
  | 'media.generation.progress'
  | 'media.generation.completed'
  | 'media.generation.failed'
  | 'tts.started'
  | 'tts.chunk.ready'
  | 'tts.completed'
  | 'tts.failed'
  | 'script.scene.changed'
  | 'script.trigger.fired'
  | 'script.milestone.reached'
  | 'relationship.updated'
  | 'relationship.milestone'
  | 'memory.fact.extracted'
  | 'memory.episode.created';

export interface PipelineEvent {
  event_type: EventType;
  data: Record<string, unknown>;
  timestamp: string;
  source: string;
  user_id?: string;
  session_id?: string;
}

export interface AudioGenerationResult {
  success: boolean;
  audio_url?: string;
  metadata?: Record<string, unknown>;
}

export interface MultimodalResult {
  text: string;
  audio_url?: string;
  image_url?: string;
  metadata?: Record<string, unknown>;
}

// SSE event listener type
type EventListener = (event: PipelineEvent) => void;

class PipelineService {
  private eventSource: EventSource | null = null;
  private listeners: Map<string, Set<EventListener>> = new Map();
  private reconnectAttempts = 0;
  private maxReconnectAttempts = 5;
  private reconnectDelay = 1000;
  
  // Connect user event stream
  connectUserEvents(onEvent?: EventListener): void {
    const baseUrl = import.meta.env.VITE_API_URL || '';
    const token = localStorage.getItem('token');
    
    const url = `${baseUrl}/api/pipeline/events/user`;
    
    this.eventSource = new EventSource(url, {
      // Note: EventSource does not support custom headers
      // Authentication must be passed via URL params or cookies
    });
    
    this.eventSource.onopen = () => {
      console.log('SSE connection established');
      this.reconnectAttempts = 0;
    };
    
    this.eventSource.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data) as PipelineEvent;
        
        // Trigger global listener
        if (onEvent) {
          onEvent(data);
        }
        
        // Trigger listeners for a specific event type
        const typeListeners = this.listeners.get(data.event_type);
        if (typeListeners) {
          typeListeners.forEach(listener => listener(data));
        }
        
        // Trigger wildcard listeners
        const allListeners = this.listeners.get('*');
        if (allListeners) {
          allListeners.forEach(listener => listener(data));
        }
      } catch (err) {
        console.error('Failed to parse SSE event:', err);
      }
    };
    
    this.eventSource.onerror = (error) => {
      console.error('SSE Connection error:', error);
      this.handleReconnect();
    };
    
    // Event types
    this.eventSource.addEventListener('connected', (event) => {
      console.log('SSE connection confirmed:', event.data);
    });
    
    this.eventSource.addEventListener('error', (event) => {
      console.error('SSE error event:', event);
    });
  }
  
  // Connect session event stream
  connectSessionEvents(sessionId: string, onEvent?: EventListener): void {
    const baseUrl = import.meta.env.VITE_API_URL || '';
    const url = `${baseUrl}/api/pipeline/events/session/${sessionId}`;
    
    this.eventSource = new EventSource(url);
    
    this.eventSource.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data) as PipelineEvent;
        if (onEvent) {
          onEvent(data);
        }
      } catch (err) {
        console.error('Failed to parse SSE event:', err);
      }
    };
    
    this.eventSource.onerror = () => {
      this.handleReconnect();
    };
  }
  
  // Disconnect
  disconnect(): void {
    if (this.eventSource) {
      this.eventSource.close();
      this.eventSource = null;
    }
    this.listeners.clear();
  }
  
  // Add event listener
  on(eventType: EventType | '*', listener: EventListener): () => void {
    if (!this.listeners.has(eventType)) {
      this.listeners.set(eventType, new Set());
    }
    this.listeners.get(eventType)!.add(listener);
    
    // Return unsubscribe function
    return () => {
      this.listeners.get(eventType)?.delete(listener);
    };
  }
  
  // Remove event listener
  off(eventType: EventType | '*', listener: EventListener): void {
    this.listeners.get(eventType)?.delete(listener);
  }
  
  // Reconnect logic
  private handleReconnect(): void {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      console.error('SSE reconnect failed: max retry attempts reached');
      return;
    }
    
    this.reconnectAttempts++;
    const delay = this.reconnectDelay * Math.pow(2, this.reconnectAttempts - 1);
    
    console.log(`SSE will reconnect in ${delay}ms before reconnect (attempt ${this.reconnectAttempts})`);
    
    setTimeout(() => {
      this.connectUserEvents();
    }, delay);
  }
  
  // Generate audio
  async generateAudio(
    text: string,
    charId: string,
    options?: {
      emotion?: string;
      relationshipScore?: number;
      sessionId?: string;
    }
  ): Promise<AudioGenerationResult> {
    const response = await api.post('/pipeline/generate/audio', {
      text,
      char_id: charId,
      emotion: options?.emotion || 'neutral',
      relationship_score: options?.relationshipScore || 50,
      session_id: options?.sessionId,
    });
    return response.data;
  }
  
  // Multimodal generation
  async generateMultimodal(
    text: string,
    charId: string,
    options?: {
      emotion?: string;
      relationshipScore?: number;
      generateAudio?: boolean;
      generateImage?: boolean;
      imagePrompt?: string;
      sessionId?: string;
    }
  ): Promise<MultimodalResult> {
    const response = await api.post('/pipeline/generate/multimodal', {
      text,
      char_id: charId,
      emotion: options?.emotion || 'neutral',
      relationship_score: options?.relationshipScore || 50,
      generate_audio: options?.generateAudio ?? true,
      generate_image: options?.generateImage ?? false,
      image_prompt: options?.imagePrompt,
      session_id: options?.sessionId,
    });
    return response.data;
  }
  
  // Publish event (internal use)
  async publishEvent(
    eventType: EventType,
    data: Record<string, unknown>,
    options?: {
      userId?: string;
      sessionId?: string;
    }
  ): Promise<{ published: boolean; subscribers: number }> {
    const response = await api.post('/pipeline/internal/publish', {
      event_type: eventType,
      data,
      user_id: options?.userId,
      session_id: options?.sessionId,
    });
    return response.data;
  }
}

// Singleton instance
export const pipelineService = new PipelineService();

export default pipelineService;

